{
  "name": "Gemini Multi-Agent Studio",
  "description": "A client-side multi-agent orchestration system where a Director AI guides two Actor AIs (Debaters or Performers) to generate dynamic scripts and debates based on user topics using Google Gemini."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AgentRole {
  DIRECTOR = 'Director',
  ACTOR_A = 'Actor A',
  ACTOR_B = 'Actor B',
}

export enum SimulationMode {
  DEBATE = 'DEBATE',
  THEATER = 'THEATER',
}

export interface Message {
  id: string;
  role: AgentRole;
  content: string;
  timestamp: number;
}

export interface SimulationState {
  isPlaying: boolean;
  round: number;
  maxRounds: number;
  topic: string;
  mode: SimulationMode;
  messages: Message[];
  currentSpeaker: AgentRole | null;
}

export type AgentConfig = {
  [key in AgentRole]: {
    name: string;
    systemInstruction: (topic: string, mode: SimulationMode) => string;
    color: string;
    avatar: string;
  };
};

import { GoogleGenAI, Type } from "@google/genai";
import { AgentRole, Message, SimulationMode } from "../types";

// Helper to get clean text from response
const getResponseText = (response: any): string => {
  if (response.text) return response.text;
  if (response.candidates?.[0]?.content?.parts?.[0]?.text) {
    return response.candidates[0].content.parts[0].text;
  }
  return "Error generating response.";
};

export const generateAgentResponse = async (
  role: AgentRole,
  systemInstruction: string,
  history: Message[],
  topic: string,
  mode: SimulationMode
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Format history for the model context
  // We provide the transcript as context so the agent knows what happened
  const contextString = history
    .map((msg) => `${msg.role}: ${msg.content}`)
    .join("\n\n");

  const prompt = `
    CURRENT CONTEXT (Transcript):
    ${contextString}

    TOPIC: ${topic}
    MODE: ${mode}

    INSTRUCTION:
    Based on the transcript above and your character defined in the system instruction, please provide your next line of dialogue.
    Keep it concise (under 100 words) and impactful.
    Do not prefix your response with your name, just speak.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.8, // Higher creativity for drama/debate
        maxOutputTokens: 300,
      },
    });

    return getResponseText(response);
  } catch (error) {
    console.error(`Error generating response for ${role}:`, error);
    return `[System Error: ${role} failed to speak. Please try again.]`;
  }
};

import { AgentRole, SimulationMode, AgentConfig } from "./types";

export const AGENT_CONFIG: AgentConfig = {
  [AgentRole.DIRECTOR]: {
    name: "Director AI",
    color: "bg-director",
    avatar: "🎬",
    systemInstruction: (topic, mode) =>
      `You are the Director and Moderator of this session. 
      Topic: "${topic}".
      Mode: "${mode}".

      Your goal is to:
      1. Introduce the topic clearly in the first turn.
      2. Briefly guide the actors if the conversation goes off track (but mostly let them speak).
      3. Provide a concluding summary when the scene ends.

      Tone: Professional, authoritative, yet creative.`,
  },
  [AgentRole.ACTOR_A]: {
    name: "Agent Alpha",
    color: "bg-actorA",
    avatar: "🤖",
    systemInstruction: (topic, mode) => {
      if (mode === SimulationMode.DEBATE) {
        return `You are a debater strictly IN FAVOR (Pro) of the topic: "${topic}".
        Your style is logical, passionate, and slightly aggressive. 
        Listen to the opponent and refute their points directly.
        Keep your responses sharp.`;
      } else {
        return `You are the Protagonist in a scene about: "${topic}".
        You are optimistic, heroic, or deeply emotional depending on the context.
        Interact with the other actor naturally.`;
      }
    },
  },
  [AgentRole.ACTOR_B]: {
    name: "Agent Beta",
    color: "bg-actorB",
    avatar: "🦊",
    systemInstruction: (topic, mode) => {
      if (mode === SimulationMode.DEBATE) {
        return `You are a debater strictly AGAINST (Con) the topic: "${topic}".
        Your style is skeptical, analytical, and witty.
        Find holes in the proponent's arguments. 
        Keep your responses sharp.`;
      } else {
        return `You are the Antagonist or Foil in a scene about: "${topic}".
        You are pessimistic, villainous, or comic relief depending on the context.
        Create conflict or contrast with the Protagonist.`;
      }
    },
  },
};

import React from "react";
import { Message, AgentRole } from "../types";
import { AGENT_CONFIG } from "../constants";

interface ChatBubbleProps {
  message: Message;
}

export const ChatBubble: React.FC<ChatBubbleProps> = ({ message }) => {
  const config = AGENT_CONFIG[message.role];
  const isDirector = message.role === AgentRole.DIRECTOR;

  return (
    <div
      className={`flex w-full mb-6 animate-fade-in ${
        isDirector ? "justify-center" : message.role === AgentRole.ACTOR_A ? "justify-start" : "justify-end"
      }`}
    >
      <div
        className={`flex max-w-[80%] md:max-w-[70%] flex-col ${
          message.role === AgentRole.ACTOR_B ? "items-end" : "items-start"
        }`}
      >
        <div className="flex items-center gap-2 mb-1">
          <span className="text-2xl filter drop-shadow-md">{config.avatar}</span>
          <span className={`text-xs font-bold uppercase tracking-wider ${
             isDirector ? "text-violet-400" : message.role === AgentRole.ACTOR_A ? "text-cyan-400" : "text-rose-400"
          }`}>
            {config.name}
          </span>
        </div>

        <div
          className={`relative p-4 rounded-2xl shadow-lg border border-opacity-10 backdrop-blur-sm ${
            isDirector
              ? "bg-violet-900/40 border-violet-500 text-center text-violet-100"
              : message.role === AgentRole.ACTOR_A
              ? "bg-cyan-900/30 border-cyan-500 text-cyan-50 rounded-tl-none"
              : "bg-rose-900/30 border-rose-500 text-rose-50 rounded-tr-none"
          }`}
        >
