                    <span className="text-xs opacity-70">Pro vs. Con logic battle</span>
                  </button>
                  <button
                    onClick={() => setSelectedMode(SimulationMode.THEATER)}
                    className={`p-4 rounded-xl border-2 transition-all duration-200 flex flex-col items-center gap-2 ${
                      selectedMode === SimulationMode.THEATER
                        ? "border-fuchsia-500 bg-fuchsia-500/10 text-fuchsia-100"
                        : "border-slate-700 bg-slate-800 text-slate-400 hover:border-slate-600"
                    }`}
                  >
                    <span className="text-2xl">🎭</span>
                    <span className="font-bold">Theater</span>
                    <span className="text-xs opacity-70">Protagonist vs. Antagonist drama</span>
                  </button>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Topic or Scenario</label>
                <div className="relative">
                  <input
                    type="text"
                    value={inputTopic}
                    onChange={(e) => setInputTopic(e.target.value)}
                    placeholder={
                      selectedMode === SimulationMode.DEBATE
                        ? "e.g., Is AI art real art?"
                        : "e.g., A detective interrogating a time traveler"
                    }
                    className="w-full bg-slate-900 border border-slate-700 rounded-xl p-4 pr-12 text-slate-100 focus:outline-none focus:ring-2 focus:ring-violet-500 transition-all placeholder-slate-600"
                    onKeyDown={(e) => e.key === 'Enter' && handleStart()}
                  />
                  <div className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500">
                    ⌨️
                  </div>
                </div>
              </div>

              <button
                onClick={handleStart}
                disabled={!inputTopic.trim()}
                className="w-full py-4 rounded-xl font-bold text-lg bg-gradient-to-r from-violet-600 to-fuchsia-600 hover:from-violet-500 hover:to-fuchsia-500 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-lg shadow-violet-900/50 flex items-center justify-center gap-2"
              >
                <span>🎬</span>
                <span>Action!</span>
              </button>
            </div>
          </div>
        )}

        {/* Script Display */}
        {(state.messages.length > 0 || state.isPlaying) && (
           <div className="flex-1 min-h-[500px] flex flex-col relative">
              <div className="flex-1 space-y-2 pb-24">
                  {state.messages.map((msg) => (
                    <ChatBubble key={msg.id} message={msg} />
                  ))}

                  {/* Loading / Typing Indicator */}
                  {state.isPlaying && state.currentSpeaker && (
                     <div className="flex w-full justify-center animate-pulse">
                        <div className={`px-4 py-2 rounded-full text-xs font-bold border ${
                            state.currentSpeaker === AgentRole.DIRECTOR ? 'border-violet-500 text-violet-400 bg-violet-900/20' :
                            state.currentSpeaker === AgentRole.ACTOR_A ? 'border-cyan-500 text-cyan-400 bg-cyan-900/20' :
                            'border-rose-500 text-rose-400 bg-rose-900/20'
                        }`}>
                           {AGENT_CONFIG[state.currentSpeaker].avatar} {AGENT_CONFIG[state.currentSpeaker].name} is thinking...
                        </div>
                     </div>
                  )}
                  <div ref={scrollRef} />
              </div>

              {/* Floating Action Bar (Stop/Reset) */}
              <div className="fixed bottom-6 left-1/2 -translate-x-1/2 flex gap-4 bg-slate-900/90 backdrop-blur border border-slate-700 p-2 rounded-2xl shadow-2xl z-50">
                 {state.isPlaying ? (
                    <button 
                        onClick={stopSimulation}
                        className="px-6 py-2 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/50 rounded-xl transition-colors font-semibold"
                    >
                        Stop Scene
                    </button>
                 ) : (
                    <button 
                        onClick={() => {
                            stopSimulation();
                            // Reset state handled by starting new simulation or reloading, 
                            // but for this UX we just clear via location reload or simple state clear
                            window.location.reload(); 
                        }}
                        className="px-6 py-2 bg-slate-700 hover:bg-slate-600 text-slate-200 rounded-xl transition-colors font-semibold flex items-center gap-2"
                    >
                        <span>🔄</span> New Scene
                    </button>
                 )}
              </div>
           </div>
        )}
      </main>
    </div>
  );
};

export default App;

