import { useState, useRef, useEffect, useCallback } from "react";
import { Message, AgentRole, SimulationMode, SimulationState, Language } from "../types";
import { AGENT_CONFIG } from "../constants";
import { generateAgentResponse } from "../services/geminiService";

export const useMultiAgentSimulation = () => {
  const [state, setState] = useState<SimulationState>({
    isPlaying: false,
    round: 0,
    maxRounds: 6, // Default turns
    topic: "",
    mode: SimulationMode.DEBATE,
    language: 'en',
    messages: [],
    currentSpeaker: null,
  });

  const stateRef = useRef(state);

  // Keep ref in sync for async operations
  useEffect(() => {
    stateRef.current = state;
  }, [state]);

  const addMessage = (role: AgentRole, content: string) => {
    const newMessage: Message = {
      id: crypto.randomUUID(),
      role,
      content,
      timestamp: Date.now(),
    };

    setState((prev) => ({
      ...prev,
      messages: [...prev.messages, newMessage],
    }));
  };

  const processTurn = useCallback(async () => {
    const currentState = stateRef.current;

    if (!currentState.isPlaying) return;

    // Determine Next Speaker Logic
    let nextSpeaker: AgentRole | null = null;
    const { messages, round, maxRounds } = currentState;

    if (messages.length === 0) {
      // Start with Director
      nextSpeaker = AgentRole.DIRECTOR;
    } else {
      const lastSpeaker = messages[messages.length - 1].role;

      if (round >= maxRounds) {
        // End with Director
        if (lastSpeaker !== AgentRole.DIRECTOR) {
          nextSpeaker = AgentRole.DIRECTOR;
        } else {
          // Simulation finished
          setState((prev) => ({ ...prev, isPlaying: false, currentSpeaker: null }));
          return;
        }
      } else {
        // Conversation Loop
        if (lastSpeaker === AgentRole.DIRECTOR) {
          nextSpeaker = AgentRole.ACTOR_A;
        } else if (lastSpeaker === AgentRole.ACTOR_A) {
          nextSpeaker = AgentRole.ACTOR_B;
        } else if (lastSpeaker === AgentRole.ACTOR_B) {
          nextSpeaker = AgentRole.ACTOR_A;
          // Increment round after B speaks (completing a pair)
           setState((prev) => ({ ...prev, round: prev.round + 1 }));
        }
      }
    }

    if (nextSpeaker) {
      setState((prev) => ({ ...prev, currentSpeaker: nextSpeaker }));

      // Prepare Prompt Data
      const config = AGENT_CONFIG[nextSpeaker];
      const systemInstruction = config.systemInstruction(currentState.topic, currentState.mode, currentState.language);

      // If it's the very last message (Director closing), append specific instruction
      const isClosing = nextSpeaker === AgentRole.DIRECTOR && round >= maxRounds;
      const effectiveInstruction = isClosing 
        ? systemInstruction + (currentState.language === 'zh-TW' ? " 這是會議的結束。請提供簡潔的總結並感謝參與者。" : " This is the end of the session. Provide a concise summary and thank the participants.")
        : systemInstruction;

      const response = await generateAgentResponse(
        nextSpeaker,
        effectiveInstruction,
        currentState.messages,
        currentState.topic,
        currentState.mode,
        currentState.language
      );

      addMessage(nextSpeaker, response);

      // Artificial delay for reading speed before next turn trigger
      setTimeout(() => {
        processTurn();
      }, 1500); 
    }
  }, []); // Dependencies are handled via ref

  const startSimulation = (topic: string, mode: SimulationMode, maxRounds: number = 6, language: Language = 'en') => {
    setState({
      isPlaying: true,
      round: 0,
      maxRounds,
      topic,
      mode,
      language,
      messages: [],
      currentSpeaker: null,
    });

    // Kickoff
    setTimeout(() => {
        processTurn();
    }, 100);
  };

  const stopSimulation = () => {
    setState((prev) => ({ ...prev, isPlaying: false, currentSpeaker: null }));
  };

  const resetSimulation = () => {
    // We preserve the language setting when resetting
    setState((prev) => ({
      isPlaying: false,
      round: 0,
      maxRounds: 6,
      topic: "",
      mode: SimulationMode.DEBATE,
      language: prev.language, 
      messages: [],
      currentSpeaker: null,
    }));
  };

  return {
    state,
    startSimulation,
    stopSimulation,
    resetSimulation,
  };
};

import React, { useState, useRef, useEffect } from "react";
import { useMultiAgentSimulation } from "./hooks/useMultiAgentSimulation";
import { SimulationMode, AgentRole, Language } from "./types";
import { ChatBubble } from "./components/ChatBubble";
import { AGENT_CONFIG, TRANSLATIONS } from "./constants";

const App: React.FC = () => {
  const { state, startSimulation, stopSimulation, resetSimulation } = useMultiAgentSimulation();
  const [inputTopic, setInputTopic] = useState("");
  const [numRounds, setNumRounds] = useState(6);
  const [selectedMode, setSelectedMode] = useState<SimulationMode>(SimulationMode.DEBATE);
  const [language, setLanguage] = useState<Language>('en'); // Local UI state for language
  const scrollRef = useRef<HTMLDivElement>(null);

  const t = TRANSLATIONS[language]; // Translation helper

  // Sync state language if playing (though usually handled by startSimulation params)
  // We keep a local 'language' state for the UI, and pass it to simulation on start.

  // Auto-scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollIntoView({ behavior: "smooth" });
    }
  }, [state.messages, state.currentSpeaker]);

  const handleStart = () => {
    if (!inputTopic.trim()) return;
    startSimulation(inputTopic, selectedMode, numRounds || 6, language);
  };

  const toggleLanguage = () => {
      setLanguage(prev => prev === 'en' ? 'zh-TW' : 'en');
  };

  return (
    <div className="min-h-screen flex flex-col items-center bg-slate-900 text-slate-100 font-sans selection:bg-violet-500 selection:text-white">
      {/* Header */}
      <header className="w-full max-w-4xl p-6 border-b border-slate-800 bg-slate-900/80 backdrop-blur sticky top-0 z-10 flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-gradient-to-br from-violet-500 to-fuchsia-500 flex items-center justify-center text-xl shadow-lg shadow-violet-500/20">
            🤖
          </div>
          <div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-violet-400 to-fuchsia-400">
              {t.appTitle}
            </h1>
            <p className="text-xs text-slate-400">{t.poweredBy}</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
            {/* Language Toggle */}
            <button 
                onClick={toggleLanguage}
                className="px-3 py-1 rounded-lg border border-slate-600 bg-slate-800 hover:bg-slate-700 text-sm font-medium transition-colors"
            >
                {language === 'en' ? '中文' : 'English'}
            </button>

            {/* Status Indicator */}
            <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-slate-800 border border-slate-700">
                <div className={`w-2 h-2 rounded-full ${state.isPlaying ? 'bg-green-500 animate-pulse' : 'bg-slate-500'}`} />
                <span className="text-xs font-medium text-slate-300">
                    {state.isPlaying ? t.sessionActive : t.ready}
                </span>
            </div>
        </div>
      </header>

      {/* Main Stage */}
      <main className="flex-1 w-full max-w-4xl p-4 md:p-6 flex flex-col gap-6">

        {/* Controls (Only visible when not playing or empty) */}
        {!state.isPlaying && state.messages.length === 0 && (
          <div className="w-full bg-slate-800/50 p-6 md:p-8 rounded-3xl border border-slate-700 shadow-xl animate-fade-in">
            <h2 className="text-2xl font-bold mb-6 text-center">{t.setStage}</h2>

            <div className="space-y-6">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">{t.selectFormat}</label>
                <div className="grid grid-cols-2 gap-4">
                  <button
                    onClick={() => setSelectedMode(SimulationMode.DEBATE)}
                    className={`p-4 rounded-xl border-2 transition-all duration-200 flex flex-col items-center gap-2 ${
                      selectedMode === SimulationMode.DEBATE
                        ? "border-violet-500 bg-violet-500/10 text-violet-100"
                        : "border-slate-700 bg-slate-800 text-slate-400 hover:border-slate-600"
                    }`}
                  >
                    <span className="text-2xl">⚖️</span>
                    <span className="font-bold">{t.debate}</span>
                    <span className="text-xs opacity-70">{t.debateDesc}</span>
                  </button>
                  <button
                    onClick={() => setSelectedMode(SimulationMode.THEATER)}
                    className={`p-4 rounded-xl border-2 transition-all duration-200 flex flex-col items-center gap-2 ${
                      selectedMode === SimulationMode.THEATER
                        ? "border-fuchsia-500 bg-fuchsia-500/10 text-fuchsia-100"
                        : "border-slate-700 bg-slate-800 text-slate-400 hover:border-slate-600"
                    }`}
                  >
                    <span className="text-2xl">🎭</span>
                    <span className="font-bold">{t.theater}</span>
                    <span className="text-xs opacity-70">{t.theaterDesc}</span>
                  </button>
                </div>
              </div>

              <div className="flex flex-col md:flex-row gap-4">
                <div className="flex-grow">
                  <label className="block text-sm font-medium text-slate-400 mb-2">{t.topicLabel}</label>
                  <div className="relative">
                    <input
                      type="text"
                      value={inputTopic}
                      onChange={(e) => setInputTopic(e.target.value)}
                      placeholder={
                        selectedMode === SimulationMode.DEBATE
                          ? t.topicPlaceholderDebate
                          : t.topicPlaceholderTheater
                      }
                      className="w-full bg-slate-900 border border-slate-700 rounded-xl p-4 pr-12 text-slate-100 focus:outline-none focus:ring-2 focus:ring-violet-500 transition-all placeholder-slate-600"
                      onKeyDown={(e) => e.key === 'Enter' && handleStart()}
                    />
                    <div className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500">
                      ⌨️
                    </div>
                  </div>
                </div>

                <div className="w-full md:w-32">
                   <label className="block text-sm font-medium text-slate-400 mb-2">{t.roundsLabel}</label>
                   <input
                      type="number"
                      min={1}
                      max={20}
                      value={numRounds}
                      onChange={(e) => setNumRounds(parseInt(e.target.value) || 0)}
                      className="w-full bg-slate-900 border border-slate-700 rounded-xl p-4 text-center text-slate-100 focus:outline-none focus:ring-2 focus:ring-violet-500 transition-all"
                   />
                </div>
              </div>

              <button
                onClick={handleStart}
                disabled={!inputTopic.trim()}
                className="w-full py-4 rounded-xl font-bold text-lg bg-gradient-to-r from-violet-600 to-fuchsia-600 hover:from-violet-500 hover:to-fuchsia-500 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-lg shadow-violet-900/50 flex items-center justify-center gap-2"
              >
                <span>🎬</span>
                <span>{t.action}</span>
              </button>
            </div>
          </div>
        )}

        {/* Script Display */}
        {(state.messages.length > 0 || state.isPlaying) && (
           <div className="flex-1 min-h-[500px] flex flex-col relative">
              <div className="flex-1 space-y-2 pb-24">
                  {state.messages.map((msg) => (
                    <ChatBubble key={msg.id} message={msg} language={state.language} />
                  ))}

                  {/* Loading / Typing Indicator */}
                  {state.isPlaying && state.currentSpeaker && (
                     <div className="flex w-full justify-center animate-pulse">
                        <div className={`px-4 py-2 rounded-full text-xs font-bold border ${
                            state.currentSpeaker === AgentRole.DIRECTOR ? 'border-violet-500 text-violet-400 bg-violet-900/20' :
                            state.currentSpeaker === AgentRole.ACTOR_A ? 'border-cyan-500 text-cyan-400 bg-cyan-900/20' :
                            'border-rose-500 text-rose-400 bg-rose-900/20'
                        }`}>
                           {AGENT_CONFIG[state.currentSpeaker].avatar} {AGENT_CONFIG[state.currentSpeaker].names[state.language]} {t.thinking}
                        </div>
                     </div>
                  )}
                  <div ref={scrollRef} />
              </div>

              {/* Floating Action Bar (Stop/Reset) */}
              <div className="fixed bottom-6 left-1/2 -translate-x-1/2 flex gap-4 bg-slate-900/90 backdrop-blur border border-slate-700 p-2 rounded-2xl shadow-2xl z-50">
                 {state.isPlaying ? (
                    <button 
                        onClick={stopSimulation}
                        className="px-6 py-2 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/50 rounded-xl transition-colors font-semibold"
                    >
                        {t.stopScene}
                    </button>
                 ) : (
                    <button 
                        onClick={() => {
                            resetSimulation();
                        }}
                        className="px-6 py-2 bg-slate-700 hover:bg-slate-600 text-slate-200 rounded-xl transition-colors font-semibold flex items-center gap-2"
                    >
                        <span>🔄</span> {t.newScene}
                    </button>
                 )}
              </div>
           </div>
        )}
      </main>
    </div>
  );
};

export default App;

