import { useState, useRef, useEffect, useCallback } from "react";
import { Message, AgentRole, SimulationMode, SimulationState, Language } from "../types";
import { AGENT_CONFIG } from "../constants";
import { generateAgentResponse } from "../services/geminiService";

export const useMultiAgentSimulation = () => {
  const [state, setState] = useState<SimulationState>({
    isPlaying: false,
    round: 0,
    maxRounds: 6, // Default turns
    topic: "",
    mode: SimulationMode.DEBATE,
    language: 'en',
    messages: [],
    currentSpeaker: null,
    maxResponseLength: 80,
    isIntervening: false,
  });

  const stateRef = useRef(state);

  // Keep ref in sync for async operations
  useEffect(() => {
    stateRef.current = state;
  }, [state]);

  const addMessage = (role: AgentRole, content: string) => {
    const newMessage: Message = {
      id: crypto.randomUUID(),
      role,
      content,
      timestamp: Date.now(),
    };

    setState((prev) => ({
      ...prev,
      messages: [...prev.messages, newMessage],
    }));
  };

  const processTurn = useCallback(async () => {
    const currentState = stateRef.current;

    if (!currentState.isPlaying) return;

    // Determine Next Speaker Logic
    let nextSpeaker: AgentRole | null = null;
    const { messages, round, maxRounds, isIntervening } = currentState;
    let overrideInstruction = "";
    let willIncrementRound = false;

    if (isIntervening) {
       nextSpeaker = AgentRole.DIRECTOR;
       overrideInstruction = currentState.language === 'zh-TW'
         ? " 【重要指令】用戶要求你介入當前對話。請總結目前的衝突點，或引導演員進入新的討論方向。請保持專業且具引導性。"
         : " [URGENT] The user has requested you to intervene. Briefly summarize the conflict so far or steer the actors in a new direction. Be professional and guiding.";

       // Reset intervention flag immediately
       setState(prev => ({ ...prev, isIntervening: false }));
    } else if (messages.length === 0) {
      // Start with Director
      nextSpeaker = AgentRole.DIRECTOR;
    } else {
      const lastSpeaker = messages[messages.length - 1].role;

      // Handle End of Game Check
      // If round limit reached, Director usually wraps up unless they just spoke
      if (round >= maxRounds) {
        if (lastSpeaker !== AgentRole.DIRECTOR) {
          nextSpeaker = AgentRole.DIRECTOR;
        } else {
          // Simulation finished
          setState((prev) => ({ ...prev, isPlaying: false, currentSpeaker: null }));
          return;
        }
      } else {
        // Conversation Loop
        if (lastSpeaker === AgentRole.DIRECTOR) {
          nextSpeaker = AgentRole.ACTOR_A;
        } else if (lastSpeaker === AgentRole.ACTOR_A) {
          nextSpeaker = AgentRole.ACTOR_B;
        } else if (lastSpeaker === AgentRole.ACTOR_B) {
          // Send to Director for round summary instead of straight to A
          nextSpeaker = AgentRole.DIRECTOR;
          willIncrementRound = true;
        }
      }
    }

    if (willIncrementRound) {
        setState((prev) => ({ ...prev, round: prev.round + 1 }));
    }

    if (nextSpeaker) {
      setState((prev) => ({ ...prev, currentSpeaker: nextSpeaker }));

      // Prepare Prompt Data
      const config = AGENT_CONFIG[nextSpeaker];
      let systemInstruction = config.systemInstruction(currentState.topic, currentState.mode, currentState.language);

      // Determine if this is the closing statement
      // It is closing if:
      // 1. We are forcibly ending (round >= maxRounds)
      // 2. OR we are about to increment round to the max (willIncrementRound && round + 1 >= maxRounds)
      const effectiveRound = willIncrementRound ? round + 1 : round;
      const isClosing = !isIntervening && nextSpeaker === AgentRole.DIRECTOR && effectiveRound >= maxRounds;

      if (isClosing) {
          systemInstruction += (currentState.language === 'zh-TW' ? " 這是會議的結束。請提供簡潔的總結並感謝參與者。" : " This is the end of the session. Provide a concise summary and thank the participants.");
      }

      if (overrideInstruction) {
          systemInstruction += " " + overrideInstruction;
      }

      const response = await generateAgentResponse(
        nextSpeaker,
        systemInstruction,
        currentState.messages,
        currentState.topic,
        currentState.mode,
        currentState.language,
        currentState.maxResponseLength
      );

      addMessage(nextSpeaker, response);

      // Artificial delay for reading speed before next turn trigger
      setTimeout(() => {
        processTurn();
      }, 1500); 
    }
  }, []); // Dependencies are handled via ref

  const startSimulation = (
    topic: string, 
    mode: SimulationMode, 
    maxRounds: number = 6, 
    language: Language = 'en',
    maxResponseLength: number = 80
  ) => {
    setState({
      isPlaying: true,
      round: 0,
      maxRounds,
      topic,
      mode,
      language,
      messages: [],
      currentSpeaker: null,
      maxResponseLength,
      isIntervening: false,
    });

    // Kickoff
    setTimeout(() => {
        processTurn();
    }, 100);
  };

  const stopSimulation = () => {
    setState((prev) => ({ ...prev, isPlaying: false, currentSpeaker: null }));
  };

  const togglePause = () => {
      setState(prev => {
          const nextIsPlaying = !prev.isPlaying;
          if (nextIsPlaying) {
              // Resuming: trigger processTurn
              setTimeout(() => {
                 processTurn();
              }, 100);
          }
          return { ...prev, isPlaying: nextIsPlaying };
      });
  };

  const triggerIntervention = () => {
      setState(prev => ({ ...prev, isIntervening: true }));
  };

  const resetSimulation = () => {
    // We preserve the language setting when resetting
    setState((prev) => ({
      isPlaying: false,
      round: 0,
      maxRounds: 6,
      topic: "",
      mode: SimulationMode.DEBATE,
      language: prev.language, 
      messages: [],
      currentSpeaker: null,
      maxResponseLength: prev.maxResponseLength,
      isIntervening: false,
    }));
  };

  return {
    state,
    startSimulation,
    stopSimulation,
    resetSimulation,
    togglePause,
    triggerIntervention,
  };
};

import { GoogleGenAI, Type } from "@google/genai";
import { AgentRole, Message, SimulationMode, Language } from "../types";

// Helper to get clean text from response
const getResponseText = (response: any): string => {
  if (response.text) return response.text;
  if (response.candidates?.[0]?.content?.parts?.[0]?.text) {
    return response.candidates[0].content.parts[0].text;
  }
  return "Error generating response.";
};

export const generateAgentResponse = async (
  role: AgentRole,
  systemInstruction: string,
  history: Message[],
  topic: string,
  mode: SimulationMode,
  language: Language,
  maxLength: number
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Format history for the model context
  // We provide the transcript as context so the agent knows what happened
  const contextString = history
    .map((msg) => `${msg.role}: ${msg.content}`)
    .join("\n\n");

  const outputLanguageInstruction = language === 'zh-TW' 
    ? "OUTPUT LANGUAGE: Traditional Chinese (Taiwan usage) / 台灣繁體中文。請使用台灣習慣用語，避免中國大陸用語。" 
    : "OUTPUT LANGUAGE: English";

  // Define length constraints based on language to keep dialogue snappy
  const lengthConstraint = language === 'zh-TW'
    ? `LENGTH CONSTRAINT: 請將回應控制在 ${maxLength} 字以內，保持對話節奏緊湊。`
    : `LENGTH CONSTRAINT: Keep your response concise, ideally under ${maxLength} words.`;

  const prompt = `
    CURRENT CONTEXT (Transcript):
    ${contextString}

    TOPIC: ${topic}
    MODE: ${mode}
    ${outputLanguageInstruction}

    INSTRUCTION:
    Based on the transcript above and your character defined in the system instruction, please provide your next line of dialogue.
    ${lengthConstraint}

    CRITICAL: Ensure you complete your sentences and thoughts. Do not stop mid-sentence. End with proper punctuation.
    Do not prefix your response with your name, just speak.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.8, // Higher creativity for drama/debate
        maxOutputTokens: 2048, // High limit to prevent cut-offs, prompt controls actual length
      },
    });

    return getResponseText(response);
  } catch (error) {
    console.error(`Error generating response for ${role}:`, error);
    return `[System Error: ${role} failed to speak. Please try again.]`;
  }
};

export type Language = 'en' | 'zh-TW';

export enum AgentRole {
  DIRECTOR = 'Director',
  ACTOR_A = 'Actor A',
  ACTOR_B = 'Actor B',
}

