      ...prev,
      messages: [...prev.messages, newMessage],
    }));
  };

  const processTurn = useCallback(async () => {
    const currentState = stateRef.current;

    if (!currentState.isPlaying) return;

    let nextSpeaker: AgentRole | null = null;
    const { messages, round, maxRounds, isIntervening } = currentState;
    let overrideInstruction = "";
    let willIncrementRound = false;

    if (isIntervening) {
       nextSpeaker = AgentRole.DIRECTOR;
       overrideInstruction = currentState.language === 'zh-TW'
         ? " 【重要指令】用戶要求你介入當前對話。請總結目前的衝突點，或引導演員進入新的討論方向。請保持專業且具引導性。"
         : " [URGENT] The user has requested you to intervene. Briefly summarize the conflict so far or steer the actors in a new direction. Be professional and guiding.";

       setState(prev => ({ ...prev, isIntervening: false }));
    } else if (messages.length === 0) {
      nextSpeaker = AgentRole.DIRECTOR;
    } else {
      const lastSpeaker = messages[messages.length - 1].role;

      if (round >= maxRounds) {
        if (lastSpeaker !== AgentRole.DIRECTOR) {
          nextSpeaker = AgentRole.DIRECTOR;
        } else {
          setState((prev) => ({ ...prev, isPlaying: false, currentSpeaker: null }));
          return;
        }
      } else {
        if (lastSpeaker === AgentRole.DIRECTOR) {
          nextSpeaker = AgentRole.ACTOR_A;
        } else if (lastSpeaker === AgentRole.ACTOR_A) {
          nextSpeaker = AgentRole.ACTOR_B;
        } else if (lastSpeaker === AgentRole.ACTOR_B) {
          nextSpeaker = AgentRole.DIRECTOR;
          willIncrementRound = true;
        }
      }
    }

    if (willIncrementRound) {
        setState((prev) => ({ ...prev, round: prev.round + 1 }));
    }

    if (nextSpeaker) {
      setState((prev) => ({ ...prev, currentSpeaker: nextSpeaker }));

      const config = AGENT_CONFIG[nextSpeaker];
      let systemInstruction = config.systemInstruction(currentState.topic, currentState.mode, currentState.language);

      const effectiveRound = willIncrementRound ? round + 1 : round;
      const isClosing = !isIntervening && nextSpeaker === AgentRole.DIRECTOR && effectiveRound >= maxRounds;

      if (isClosing) {
          systemInstruction += (currentState.language === 'zh-TW' ? " 這是會議的結束。請提供簡潔的總結並感謝參與者。" : " This is the end of the session. Provide a concise summary and thank the participants.");
      }

      if (overrideInstruction) {
          systemInstruction += " " + overrideInstruction;
      }

      // 1. Generate Text
      const response = await generateAgentResponse(
        nextSpeaker,
        systemInstruction,
        currentState.messages,
        currentState.topic,
        currentState.mode,
        currentState.language,
        currentState.maxResponseLength
      );

      addMessage(nextSpeaker, response);

      // 2. Generate and Play Audio (Blocking if not muted)
      if (!currentState.isMuted) {
          // Pass the plain text response to TTS
          await playTextToSpeech(response, config.voiceName);
      }

      // 3. Queue next turn
      // Use a short delay if audio played (it already blocked), or longer if muted for readability
      const nextTurnDelay = currentState.isMuted ? 2000 : 500;

      setTimeout(() => {
        processTurn();
      }, nextTurnDelay); 
    }
  }, []);

  const startSimulation = (
    topic: string, 
    mode: SimulationMode, 
    maxRounds: number = 6, 
    language: Language = 'en',
    maxResponseLength: number = 80
  ) => {
    // Initialize Audio Context on user interaction (Start button)
    initAudioContext();

    setState({
      isPlaying: true,
      round: 0,
      maxRounds,
      topic,
      mode,
      language,
      messages: [],
      currentSpeaker: null,
      maxResponseLength,
      isIntervening: false,
      isMuted: state.isMuted, // Preserve mute state
    });

    setTimeout(() => {
        processTurn();
    }, 100);
  };

  const stopSimulation = () => {
    setState((prev) => ({ ...prev, isPlaying: false, currentSpeaker: null }));
  };

  const togglePause = () => {
      setState(prev => {
          const nextIsPlaying = !prev.isPlaying;
          if (nextIsPlaying) {
             initAudioContext(); // Ensure context is awake
              setTimeout(() => {
                 processTurn();
              }, 100);
          }
          return { ...prev, isPlaying: nextIsPlaying };
      });
  };

  const toggleMute = () => {
      setState(prev => ({ ...prev, isMuted: !prev.isMuted }));
  };

  const triggerIntervention = () => {
      setState(prev => ({ ...prev, isIntervening: true }));
  };

  const resetSimulation = () => {
    setState((prev) => ({
      isPlaying: false,
      round: 0,
      maxRounds: 6,
      topic: "",
      mode: SimulationMode.DEBATE,
      language: prev.language, 
      messages: [],
      currentSpeaker: null,
      maxResponseLength: prev.maxResponseLength,
      isIntervening: false,
      isMuted: prev.isMuted,
    }));
  };

  return {
    state,
    startSimulation,
    stopSimulation,
    resetSimulation,
    togglePause,
    triggerIntervention,
    toggleMute,
  };
};

import React, { useState, useRef, useEffect } from "react";
import { useMultiAgentSimulation } from "./hooks/useMultiAgentSimulation";
import { SimulationMode, AgentRole, Language } from "./types";
import { ChatBubble } from "./components/ChatBubble";
import { AGENT_CONFIG, TRANSLATIONS, RANDOM_TOPICS } from "./constants";

const MAX_TOPIC_LENGTH = 100;

const App: React.FC = () => {
  const { state, startSimulation, stopSimulation, resetSimulation, togglePause, triggerIntervention, toggleMute } = useMultiAgentSimulation();
  const [inputTopic, setInputTopic] = useState("");
  const [numRounds, setNumRounds] = useState(6);
  const [selectedMode, setSelectedMode] = useState<SimulationMode>(SimulationMode.DEBATE);
  const [language, setLanguage] = useState<Language>('en'); 
  // Use string | number to allow empty input while typing
  const [maxLen, setMaxLen] = useState<number | string>(80);
  const scrollRef = useRef<HTMLDivElement>(null);

  const t = TRANSLATIONS[language]; 

  // Auto-scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollIntoView({ behavior: "smooth" });
    }
  }, [state.messages, state.currentSpeaker]);

  // Update default max length when language changes
  useEffect(() => {
    if (language === 'zh-TW') {
        setMaxLen(150);
    } else {
        setMaxLen(80);
    }
  }, [language]);

  const handleStart = () => {
    if (!inputTopic.trim()) return;
    // Ensure maxLen is a valid number before starting
    const finalLen = Number(maxLen) || (language === 'zh-TW' ? 150 : 80);
    startSimulation(inputTopic, selectedMode, numRounds || 6, language, finalLen);
  };

  const toggleLanguage = () => {
      setLanguage(prev => prev === 'en' ? 'zh-TW' : 'en');
  };

  const handleRandomTopic = () => {
      const topics = RANDOM_TOPICS[language][selectedMode];
      const randomTopic = topics[Math.floor(Math.random() * topics.length)];
      setInputTopic(randomTopic);
  };

  const handleMaxLenBlur = () => {
    let val = Number(maxLen);
    if (!val || val < 10) val = 10;
    if (val > 1000) val = 1000;
    setMaxLen(val);
  };

