            <p className="text-xs text-slate-400">{t.poweredBy}</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
            {/* Mute Toggle */}
            <button
              onClick={toggleMute}
              className="p-2 rounded-lg text-slate-400 hover:text-slate-100 hover:bg-slate-800 transition-colors"
              title={state.isMuted ? t.unmute : t.mute}
            >
               {state.isMuted ? "🔇" : "🔊"}
            </button>

            {/* Language Toggle */}
            <button 
                onClick={toggleLanguage}
                className="px-3 py-1 rounded-lg border border-slate-600 bg-slate-800 hover:bg-slate-700 text-sm font-medium transition-colors"
            >
                {language === 'en' ? '中文' : 'English'}
            </button>

            {/* Status Indicator */}
            <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-slate-800 border border-slate-700">
                <div className={`w-2 h-2 rounded-full ${state.isPlaying ? 'bg-green-500 animate-pulse' : 'bg-slate-500'}`} />
                <span className="text-xs font-medium text-slate-300">
                    {state.isPlaying ? t.sessionActive : (state.messages.length > 0 ? t.pause : t.ready)}
                </span>
            </div>
        </div>
      </header>

      {/* Main Stage */}
      <main className="flex-1 w-full max-w-4xl p-4 md:p-6 flex flex-col gap-6">

        {/* Controls (Only visible when not playing or empty) */}
        {!state.isPlaying && state.messages.length === 0 && (
          <div className="w-full bg-slate-800/50 p-6 md:p-8 rounded-3xl border border-slate-700 shadow-xl animate-fade-in">
            <h2 className="text-2xl font-bold mb-6 text-center">{t.setStage}</h2>

            <div className="space-y-6">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">{t.selectFormat}</label>
                <div className="grid grid-cols-2 gap-4">
                  <button
                    onClick={() => setSelectedMode(SimulationMode.DEBATE)}
                    className={`p-4 rounded-xl border-2 transition-all duration-200 flex flex-col items-center gap-2 ${
                      selectedMode === SimulationMode.DEBATE
                        ? "border-violet-500 bg-violet-500/10 text-violet-100"
                        : "border-slate-700 bg-slate-800 text-slate-400 hover:border-slate-600"
                    }`}
                  >
                    <span className="text-2xl">⚖️</span>
                    <span className="font-bold">{t.debate}</span>
                    <span className="text-xs opacity-70">{t.debateDesc}</span>
                  </button>
                  <button
                    onClick={() => setSelectedMode(SimulationMode.THEATER)}
                    className={`p-4 rounded-xl border-2 transition-all duration-200 flex flex-col items-center gap-2 ${
                      selectedMode === SimulationMode.THEATER
                        ? "border-fuchsia-500 bg-fuchsia-500/10 text-fuchsia-100"
                        : "border-slate-700 bg-slate-800 text-slate-400 hover:border-slate-600"
                    }`}
                  >
                    <span className="text-2xl">🎭</span>
                    <span className="font-bold">{t.theater}</span>
                    <span className="text-xs opacity-70">{t.theaterDesc}</span>
                  </button>
                </div>
              </div>

              <div className="flex flex-col md:flex-row gap-4">
                <div className="flex-grow">
                  <label className="block text-sm font-medium text-slate-400 mb-2 flex items-center justify-between">
                      {t.topicLabel}
                      <button 
                        onClick={handleRandomTopic}
                        className="text-violet-400 hover:text-violet-300 text-xs flex items-center gap-1 transition-colors"
                      >
                         <span>🎲</span> {t.randomTopic}
                      </button>
                  </label>
                  <div className="relative">
                    <input
                      type="text"
                      maxLength={MAX_TOPIC_LENGTH}
                      value={inputTopic}
                      onChange={(e) => setInputTopic(e.target.value)}
                      placeholder={
                        selectedMode === SimulationMode.DEBATE
                          ? t.topicPlaceholderDebate
                          : t.topicPlaceholderTheater
                      }
                      className="w-full bg-slate-900 border border-slate-700 rounded-xl p-4 pr-16 text-slate-100 focus:outline-none focus:ring-2 focus:ring-violet-500 transition-all placeholder-slate-600"
                      onKeyDown={(e) => e.key === 'Enter' && handleStart()}
                    />
                    <div className={`absolute right-4 top-1/2 -translate-y-1/2 text-xs font-mono ${
                        inputTopic.length >= MAX_TOPIC_LENGTH ? 'text-red-400' : 'text-slate-500'
                    }`}>
                      {inputTopic.length}/{MAX_TOPIC_LENGTH}
                    </div>
                  </div>
                </div>

                <div className="w-full md:w-28">
                   <label className="block text-sm font-medium text-slate-400 mb-2">{t.roundsLabel}</label>
                   <input
                      type="number"
                      min={1}
                      max={20}
                      value={numRounds}
                      onChange={(e) => setNumRounds(parseInt(e.target.value) || 0)}
                      className="w-full bg-slate-900 border border-slate-700 rounded-xl p-4 text-center text-slate-100 focus:outline-none focus:ring-2 focus:ring-violet-500 transition-all"
                   />
                </div>

                 <div className="w-full md:w-36">
                   <label className="block text-sm font-medium text-slate-400 mb-2">{t.maxLengthLabel}</label>
                   <div className="relative">
                       <input
                          type="number"
                          min={10}
                          max={500}
                          step={10}
                          value={maxLen}
                          onChange={(e) => setMaxLen(e.target.value)}
                          onBlur={handleMaxLenBlur}
                          className="w-full bg-slate-900 border border-slate-700 rounded-xl p-4 text-center text-slate-100 focus:outline-none focus:ring-2 focus:ring-violet-500 transition-all"
                       />
                       <span className="absolute right-3 top-1/2 -translate-y-1/2 text-xs text-slate-500 pointer-events-none">
                           {t.wordUnit}
                       </span>
                   </div>
                </div>
              </div>

              <button
                onClick={handleStart}
                disabled={!inputTopic.trim()}
                className="w-full py-4 rounded-xl font-bold text-lg bg-gradient-to-r from-violet-600 to-fuchsia-600 hover:from-violet-500 hover:to-fuchsia-500 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-lg shadow-violet-900/50 flex items-center justify-center gap-2"
              >
                <span>🎬</span>
                <span>{t.action}</span>
              </button>
            </div>
          </div>
        )}

        {/* Script Display */}
        {(state.messages.length > 0 || state.isPlaying) && (
           <div className="flex-1 min-h-[500px] flex flex-col relative">
              <div className="flex-1 space-y-2 pb-24">
                  {state.messages.map((msg) => (
                    <ChatBubble key={msg.id} message={msg} language={state.language} />
                  ))}

                  {/* Loading / Typing Indicator */}
                  {state.isPlaying && state.currentSpeaker && (
                     <div className="flex w-full justify-center animate-pulse">
                        <div className={`px-4 py-2 rounded-full text-xs font-bold border ${
                            state.currentSpeaker === AgentRole.DIRECTOR ? 'border-violet-500 text-violet-400 bg-violet-900/20' :
                            state.currentSpeaker === AgentRole.ACTOR_A ? 'border-cyan-500 text-cyan-400 bg-cyan-900/20' :
                            'border-rose-500 text-rose-400 bg-rose-900/20'
                        }`}>
                           {AGENT_CONFIG[state.currentSpeaker].avatar} {AGENT_CONFIG[state.currentSpeaker].names[state.language]} {t.thinking}
                        </div>
                     </div>
                  )}
                  <div ref={scrollRef} />
              </div>

              {/* Floating Action Bar */}
              <div className="fixed bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-3 bg-slate-900/95 backdrop-blur-md border border-slate-700/50 p-2 pl-3 pr-2 rounded-2xl shadow-2xl z-50 ring-1 ring-white/10">

                 {/* Intervene Button */}
                 <button
                   onClick={() => triggerIntervention()}
                   disabled={!state.isPlaying || state.isIntervening}
                   title={t.interveneTooltip}
                   className={`flex flex-col items-center justify-center w-12 h-12 rounded-xl transition-all ${
                     state.isIntervening 
                      ? "bg-violet-500 text-white animate-pulse" 
                      : "bg-slate-800 hover:bg-violet-600/20 text-slate-300 hover:text-violet-300 border border-slate-700 hover:border-violet-500/50"
                   } disabled:opacity-30 disabled:cursor-not-allowed`}
                 >
                   <span className="text-xl">📢</span>
                 </button>

                 <div className="h-8 w-px bg-slate-700 mx-1"></div>

                 {/* Pause / Resume */}
                 <button 
                    onClick={togglePause}
                    className={`flex items-center gap-2 px-6 h-12 rounded-xl font-bold transition-all ${
                       state.isPlaying 
                         ? "bg-amber-500/10 hover:bg-amber-500/20 text-amber-400 border border-amber-500/30 hover:border-amber-500" 
                         : "bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400 border border-emerald-500/30 hover:border-emerald-500"
                    }`}
                 >
                    <span className="text-xl">{state.isPlaying ? "⏸" : "▶️"}</span>
                    <span>{state.isPlaying ? t.pause : t.resume}</span>
                 </button>

                 {/* Reset / New Scene */}
                 {!state.isPlaying && (
                     <button 
                        onClick={resetSimulation}
                        className="flex items-center gap-2 px-4 h-12 bg-slate-800 hover:bg-slate-700 text-slate-300 border border-slate-700 hover:border-slate-600 rounded-xl transition-colors font-semibold"
                    >
                        <span>🔄</span>
                        <span className="hidden sm:inline">{t.newScene}</span>
                    </button>
                 )}
              </div>
           </div>
        )}
      </main>
    </div>
  );
};

export default App;

export type Language = 'en' | 'zh-TW';

export enum AgentRole {
  DIRECTOR = 'Director',
  ACTOR_A = 'Actor A',
  ACTOR_B = 'Actor B',
}

export enum SimulationMode {
  DEBATE = 'DEBATE',
  THEATER = 'THEATER',
}

export interface Message {
  id: string;
  role: AgentRole;
  content: string;
  timestamp: number;
}

export interface SimulationState {
  isPlaying: boolean;
  round: number;
  maxRounds: number;
  topic: string;
  mode: SimulationMode;
  language: Language;
  messages: Message[];
  currentSpeaker: AgentRole | null;
  maxResponseLength: number;
  isIntervening: boolean;
  isMuted: boolean;
  agentVoices: Record<AgentRole, string>;
}

export type AgentConfig = {
  [key in AgentRole]: {
    names: Record<Language, string>;
    systemInstruction: (topic: string, mode: SimulationMode, lang: Language) => string;
    color: string;
    avatar: string;
    voiceName: string; // Default voice
  };
};

import { useState, useRef, useEffect, useCallback } from "react";
import { Message, AgentRole, SimulationMode, SimulationState, Language } from "../types";
import { AGENT_CONFIG } from "../constants";
import { generateAgentResponse } from "../services/geminiService";
import { playTextToSpeech, initAudioContext } from "../services/ttsService";

export const useMultiAgentSimulation = () => {
  const [state, setState] = useState<SimulationState>({
    isPlaying: false,
    round: 0,
    maxRounds: 6,
    topic: "",
    mode: SimulationMode.DEBATE,
    language: 'en',
    messages: [],
    currentSpeaker: null,
    maxResponseLength: 80,
    isIntervening: false,
    isMuted: false, 
    agentVoices: {
        [AgentRole.DIRECTOR]: AGENT_CONFIG[AgentRole.DIRECTOR].voiceName,
        [AgentRole.ACTOR_A]: AGENT_CONFIG[AgentRole.ACTOR_A].voiceName,
        [AgentRole.ACTOR_B]: AGENT_CONFIG[AgentRole.ACTOR_B].voiceName,
    }
  });

  const stateRef = useRef(state);

  useEffect(() => {
    stateRef.current = state;
  }, [state]);

  const addMessage = (role: AgentRole, content: string) => {
    const newMessage: Message = {
      id: crypto.randomUUID(),
      role,
      content,
      timestamp: Date.now(),
    };

    setState((prev) => ({
      ...prev,
      messages: [...prev.messages, newMessage],
    }));
  };

  const processTurn = useCallback(async () => {
    const currentState = stateRef.current;

    if (!currentState.isPlaying) return;

    let nextSpeaker: AgentRole | null = null;
    const { messages, round, maxRounds, isIntervening } = currentState;
    let overrideInstruction = "";
    let willIncrementRound = false;

    if (isIntervening) {
       nextSpeaker = AgentRole.DIRECTOR;
       overrideInstruction = currentState.language === 'zh-TW'
         ? " 【重要指令】用戶要求你介入當前對話。請總結目前的衝突點，或引導演員進入新的討論方向。請保持專業且具引導性。"
         : " [URGENT] The user has requested you to intervene. Briefly summarize the conflict so far or steer the actors in a new direction. Be professional and guiding.";

       setState(prev => ({ ...prev, isIntervening: false }));
    } else if (messages.length === 0) {
      nextSpeaker = AgentRole.DIRECTOR;
    } else {
      const lastSpeaker = messages[messages.length - 1].role;

      if (round >= maxRounds) {
        if (lastSpeaker !== AgentRole.DIRECTOR) {
          nextSpeaker = AgentRole.DIRECTOR;
        } else {
          setState((prev) => ({ ...prev, isPlaying: false, currentSpeaker: null }));
          return;
        }
      } else {
        if (lastSpeaker === AgentRole.DIRECTOR) {
          nextSpeaker = AgentRole.ACTOR_A;
        } else if (lastSpeaker === AgentRole.ACTOR_A) {
          nextSpeaker = AgentRole.ACTOR_B;
        } else if (lastSpeaker === AgentRole.ACTOR_B) {
          nextSpeaker = AgentRole.DIRECTOR;
          willIncrementRound = true;
        }
      }
    }

    if (willIncrementRound) {
        setState((prev) => ({ ...prev, round: prev.round + 1 }));
    }

    if (nextSpeaker) {
      setState((prev) => ({ ...prev, currentSpeaker: nextSpeaker }));

      const config = AGENT_CONFIG[nextSpeaker];
      let systemInstruction = config.systemInstruction(currentState.topic, currentState.mode, currentState.language);

      const effectiveRound = willIncrementRound ? round + 1 : round;
      const isClosing = !isIntervening && nextSpeaker === AgentRole.DIRECTOR && effectiveRound >= maxRounds;

      if (isClosing) {
          systemInstruction += (currentState.language === 'zh-TW' ? " 這是會議的結束。請提供簡潔的總結並感謝參與者。" : " This is the end of the session. Provide a concise summary and thank the participants.");
      }

      if (overrideInstruction) {
          systemInstruction += " " + overrideInstruction;
      }

      // 1. Generate Text
      const response = await generateAgentResponse(
        nextSpeaker,
        systemInstruction,
        currentState.messages,
        currentState.topic,
        currentState.mode,
        currentState.language,
        currentState.maxResponseLength
      );

      addMessage(nextSpeaker, response);

      // 2. Generate and Play Audio (Blocking if not muted)
      if (!currentState.isMuted) {
          // Use the selected voice from state
          const selectedVoice = currentState.agentVoices[nextSpeaker];
          await playTextToSpeech(response, selectedVoice);
      }

      // 3. Queue next turn
      // Use a short delay if audio played (it already blocked), or longer if muted for readability
      const nextTurnDelay = currentState.isMuted ? 2000 : 500;

      setTimeout(() => {
        processTurn();
      }, nextTurnDelay); 
    }
  }, []);

  const startSimulation = (
    topic: string, 
    mode: SimulationMode, 
    maxRounds: number = 6, 
    language: Language = 'en',
    maxResponseLength: number = 80
  ) => {
    // Initialize Audio Context on user interaction (Start button)
    initAudioContext();

    setState(prev => ({
      isPlaying: true,
      round: 0,
      maxRounds,
      topic,
      mode,
      language,
      messages: [],
      currentSpeaker: null,
      maxResponseLength,
      isIntervening: false,
      isMuted: prev.isMuted, 
      agentVoices: prev.agentVoices // Preserve voice selection
    }));

    setTimeout(() => {
        processTurn();
    }, 100);
  };

  const stopSimulation = () => {
    setState((prev) => ({ ...prev, isPlaying: false, currentSpeaker: null }));
  };

  const togglePause = () => {
      setState(prev => {
          const nextIsPlaying = !prev.isPlaying;
          if (nextIsPlaying) {
             initAudioContext(); // Ensure context is awake
              setTimeout(() => {
                 processTurn();
              }, 100);
          }
          return { ...prev, isPlaying: nextIsPlaying };
      });
  };

  const toggleMute = () => {
      setState(prev => ({ ...prev, isMuted: !prev.isMuted }));
  };

  const triggerIntervention = () => {
      setState(prev => ({ ...prev, isIntervening: true }));
  };

  const resetSimulation = () => {
    setState((prev) => ({
      isPlaying: false,
      round: 0,
      maxRounds: 6,
      topic: "",
      mode: SimulationMode.DEBATE,
      language: prev.language, 
      messages: [],
      currentSpeaker: null,
      maxResponseLength: prev.maxResponseLength,
      isIntervening: false,
      isMuted: prev.isMuted,
      agentVoices: prev.agentVoices, // Keep voices
    }));
  };

  const setAgentVoice = (role: AgentRole, voice: string) => {
    setState(prev => ({
        ...prev,
        agentVoices: {
            ...prev.agentVoices,
            [role]: voice
        }
    }));
  };

  return {
    state,
    startSimulation,
    stopSimulation,
    resetSimulation,
    togglePause,
    triggerIntervention,
    toggleMute,
    setAgentVoice,
  };
};

