export default App;

export type Language = 'en' | 'zh-TW';

export enum AgentRole {
  DIRECTOR = 'Director',
  ACTOR_A = 'Actor A',
  ACTOR_B = 'Actor B',
}

export enum SimulationMode {
  DEBATE = 'DEBATE',
  THEATER = 'THEATER',
}

export interface Message {
  id: string;
  role: AgentRole;
  content: string;
  timestamp: number;
  audioBase64?: string;
}

export interface SimulationState {
  isPlaying: boolean;
  round: number;
  maxRounds: number;
  topic: string;
  mode: SimulationMode;
  language: Language;
  messages: Message[];
  currentSpeaker: AgentRole | null;
  maxResponseLength: number;
  isIntervening: boolean;
  isMuted: boolean;
  agentVoices: Record<AgentRole, string>;
}

export type AgentConfig = {
  [key in AgentRole]: {
    names: Record<Language, string>;
    systemInstruction: (topic: string, mode: SimulationMode, lang: Language) => string;
    color: string;
    avatar: string;
    voiceName: string; // Default voice
  };
};

import { GoogleGenAI, Modality } from "@google/genai";

let audioContext: AudioContext | null = null;

// Initialize Audio Context (must be called after user interaction)
export const initAudioContext = () => {
  if (!audioContext) {
    audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
      sampleRate: 24000, // Matches Gemini TTS output
    });
  } else if (audioContext.state === "suspended") {
    audioContext.resume();
  }
  return audioContext;
};

// Base64 decoding helper from documentation
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// Audio decoding helper from documentation
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

// Fetch TTS Audio Data (Base64)
export const fetchTTS = async (text: string, voiceName: string): Promise<string | undefined> => {
  if (!text.trim()) return undefined;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (error) {
    console.error("TTS Generation Error:", error);
    return undefined;
  }
};

// Play existing Base64 Audio Data
export const playAudioData = async (base64Audio: string): Promise<void> => {
  const ctx = initAudioContext();
  if (!ctx) return;

  try {
    const audioBuffer = await decodeAudioData(
      decode(base64Audio),
      ctx,
      24000,
      1,
    );

    return new Promise((resolve) => {
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);

      source.onended = () => {
        resolve();
      };

      source.start();
    });
  } catch (error) {
    console.error("Audio Playback Error:", error);
    return Promise.resolve();
  }
};

// Deprecated: Wrapper for backward compatibility if needed, but we will update hooks to use split functions
export const playTextToSpeech = async (text: string, voiceName: string): Promise<void> => {
    const data = await fetchTTS(text, voiceName);
    if (data) {
        await playAudioData(data);
    }
};

import { useState, useRef, useEffect, useCallback } from "react";
import { Message, AgentRole, SimulationMode, SimulationState, Language } from "../types";
import { AGENT_CONFIG } from "../constants";
import { generateAgentResponse } from "../services/geminiService";
import { fetchTTS, playAudioData, initAudioContext } from "../services/ttsService";

export const useMultiAgentSimulation = () => {
  const [state, setState] = useState<SimulationState>({
    isPlaying: false,
    round: 0,
    maxRounds: 6,
    topic: "",
    mode: SimulationMode.DEBATE,
    language: 'en',
    messages: [],
    currentSpeaker: null,
    maxResponseLength: 80,
    isIntervening: false,
    isMuted: false, 
    agentVoices: {
        [AgentRole.DIRECTOR]: AGENT_CONFIG[AgentRole.DIRECTOR].voiceName,
        [AgentRole.ACTOR_A]: AGENT_CONFIG[AgentRole.ACTOR_A].voiceName,
        [AgentRole.ACTOR_B]: AGENT_CONFIG[AgentRole.ACTOR_B].voiceName,
    }
  });

  const stateRef = useRef(state);

  useEffect(() => {
    stateRef.current = state;
  }, [state]);

  const addMessage = (role: AgentRole, content: string, audioBase64?: string) => {
    const newMessage: Message = {
      id: crypto.randomUUID(),
      role,
      content,
      timestamp: Date.now(),
      audioBase64,
    };

    setState((prev) => ({
      ...prev,
      messages: [...prev.messages, newMessage],
    }));
  };

  const processTurn = useCallback(async () => {
    const currentState = stateRef.current;

    if (!currentState.isPlaying) return;

    let nextSpeaker: AgentRole | null = null;
    const { messages, round, maxRounds, isIntervening } = currentState;
    let overrideInstruction = "";
    let willIncrementRound = false;

    if (isIntervening) {
       nextSpeaker = AgentRole.DIRECTOR;
       overrideInstruction = currentState.language === 'zh-TW'
         ? " 【重要指令】用戶要求你介入當前對話。請總結目前的衝突點，或引導演員進入新的討論方向。請保持專業且具引導性。"
         : " [URGENT] The user has requested you to intervene. Briefly summarize the conflict so far or steer the actors in a new direction. Be professional and guiding.";

       setState(prev => ({ ...prev, isIntervening: false }));
    } else if (messages.length === 0) {
      nextSpeaker = AgentRole.DIRECTOR;
    } else {
      const lastSpeaker = messages[messages.length - 1].role;

      if (round >= maxRounds) {
        if (lastSpeaker !== AgentRole.DIRECTOR) {
          nextSpeaker = AgentRole.DIRECTOR;
        } else {
          setState((prev) => ({ ...prev, isPlaying: false, currentSpeaker: null }));
          return;
        }
      } else {
        if (lastSpeaker === AgentRole.DIRECTOR) {
          nextSpeaker = AgentRole.ACTOR_A;
        } else if (lastSpeaker === AgentRole.ACTOR_A) {
          nextSpeaker = AgentRole.ACTOR_B;
        } else if (lastSpeaker === AgentRole.ACTOR_B) {
          nextSpeaker = AgentRole.DIRECTOR;
          willIncrementRound = true;
        }
      }
    }

    if (willIncrementRound) {
        setState((prev) => ({ ...prev, round: prev.round + 1 }));
    }

    if (nextSpeaker) {
      setState((prev) => ({ ...prev, currentSpeaker: nextSpeaker }));

      const config = AGENT_CONFIG[nextSpeaker];
      let systemInstruction = config.systemInstruction(currentState.topic, currentState.mode, currentState.language);

      const effectiveRound = willIncrementRound ? round + 1 : round;
      const isClosing = !isIntervening && nextSpeaker === AgentRole.DIRECTOR && effectiveRound >= maxRounds;

      if (isClosing) {
          systemInstruction += (currentState.language === 'zh-TW' ? " 這是會議的結束。請提供簡潔的總結並感謝參與者。" : " This is the end of the session. Provide a concise summary and thank the participants.");
      }

      if (overrideInstruction) {
          systemInstruction += " " + overrideInstruction;
      }

      // 1. Generate Text
      const response = await generateAgentResponse(
        nextSpeaker,
        systemInstruction,
        currentState.messages,
        currentState.topic,
        currentState.mode,
        currentState.language,
        currentState.maxResponseLength
      );

      // 2. Generate Audio (Pre-fetch before adding message for smoother UX, or parallel? 
      //    Synchronous is safer to ensure message has audio when displayed)
      const selectedVoice = currentState.agentVoices[nextSpeaker];
      const audioData = await fetchTTS(response, selectedVoice);

      addMessage(nextSpeaker, response, audioData);

      // 3. Play Audio (Blocking if not muted)
      if (!currentState.isMuted && audioData) {
          await playAudioData(audioData);
      }

      // 4. Queue next turn
      // Use a short delay if audio played (it already blocked), or longer if muted for readability
      const nextTurnDelay = currentState.isMuted ? 2000 : 500;

      setTimeout(() => {
        processTurn();
      }, nextTurnDelay); 
    }
  }, []);

  const startSimulation = (
    topic: string, 
    mode: SimulationMode, 
    maxRounds: number = 6, 
    language: Language = 'en',
    maxResponseLength: number = 80
  ) => {
    // Initialize Audio Context on user interaction (Start button)
    initAudioContext();

    setState(prev => ({
      isPlaying: true,
      round: 0,
      maxRounds,
      topic,
      mode,
      language,
      messages: [],
      currentSpeaker: null,
      maxResponseLength,
      isIntervening: false,
      isMuted: prev.isMuted, 
      agentVoices: prev.agentVoices // Preserve voice selection
    }));

    setTimeout(() => {
        processTurn();
    }, 100);
  };

  const stopSimulation = () => {
    setState((prev) => ({ ...prev, isPlaying: false, currentSpeaker: null }));
  };

  const togglePause = () => {
      setState(prev => {
          const nextIsPlaying = !prev.isPlaying;
          if (nextIsPlaying) {
             initAudioContext(); // Ensure context is awake
              setTimeout(() => {
                 processTurn();
              }, 100);
          }
          return { ...prev, isPlaying: nextIsPlaying };
      });
  };

  const toggleMute = () => {
      setState(prev => ({ ...prev, isMuted: !prev.isMuted }));
  };

  const triggerIntervention = () => {
      setState(prev => ({ ...prev, isIntervening: true }));
  };

  const resetSimulation = () => {
    setState((prev) => ({
      isPlaying: false,
      round: 0,
      maxRounds: 6,
      topic: "",
      mode: SimulationMode.DEBATE,
      language: prev.language, 
      messages: [],
      currentSpeaker: null,
      maxResponseLength: prev.maxResponseLength,
      isIntervening: false,
      isMuted: prev.isMuted,
      agentVoices: prev.agentVoices, // Keep voices
    }));
  };

  const setAgentVoice = (role: AgentRole, voice: string) => {
    setState(prev => ({
        ...prev,
        agentVoices: {
            ...prev.agentVoices,
            [role]: voice
        }
    }));
  };

  return {
    state,
    startSimulation,
    stopSimulation,
    resetSimulation,
    togglePause,
    triggerIntervention,
    toggleMute,
    setAgentVoice,
  };
};

