      currentSpeaker: null,
      maxResponseLength,
      isIntervening: false,
      isMuted: prev.isMuted, 
      agentVoices: prev.agentVoices 
    }));

    setTimeout(() => {
        processTurn();
    }, 100);
  };

  const stopSimulation = () => {
    stopCurrentAudio();
    setState((prev) => ({ ...prev, isPlaying: false, currentSpeaker: null }));
  };

  const togglePause = () => {
      // Immediate action based on current state
      if (state.isPlaying) {
          stopCurrentAudio();
      }

      setState(prev => {
          const nextIsPlaying = !prev.isPlaying;

          if (nextIsPlaying) {
             initAudioContext(); 
              setTimeout(() => {
                 processTurn();
              }, 100);
          }

          return { ...prev, isPlaying: nextIsPlaying };
      });
  };

  const toggleMute = () => {
      // Immediate action based on current state
      if (!state.isMuted) {
          stopCurrentAudio();
      }

      setState(prev => ({ ...prev, isMuted: !prev.isMuted }));
  };

  const triggerIntervention = () => {
      setState(prev => ({ ...prev, isIntervening: true }));
  };

  const resetSimulation = () => {
    stopCurrentAudio();
    setState((prev) => ({
      isPlaying: false,
      round: 0,
      maxRounds: 6,
      topic: "",
      mode: SimulationMode.DEBATE,
      language: prev.language, 
      messages: [],
      currentSpeaker: null,
      maxResponseLength: prev.maxResponseLength,
      isIntervening: false,
      isMuted: prev.isMuted,
      agentVoices: prev.agentVoices, 
    }));
  };

  const setAgentVoice = (role: AgentRole, voice: string) => {
    setState(prev => ({
        ...prev,
        agentVoices: {
            ...prev.agentVoices,
            [role]: voice
        }
    }));
  };

  return {
    state,
    startSimulation,
    stopSimulation,
    resetSimulation,
    togglePause,
    triggerIntervention,
    toggleMute,
    setAgentVoice,
  };
};

export type Language = 'en' | 'zh-TW';

export enum AgentRole {
  DIRECTOR = 'Director',
  ACTOR_A = 'Actor A',
  ACTOR_B = 'Actor B',
}

export enum SimulationMode {
  DEBATE = 'DEBATE',
  THEATER = 'THEATER',
  EDUCATION = 'EDUCATION',
}

export interface Message {
  id: string;
  role: AgentRole;
  content: string;
  timestamp: number;
  audioBase64?: string;
}

export interface SimulationState {
  isPlaying: boolean;
  round: number;
  maxRounds: number;
  topic: string;
  mode: SimulationMode;
  language: Language;
  messages: Message[];
  currentSpeaker: AgentRole | null;
  maxResponseLength: number;
  isIntervening: boolean;
  isMuted: boolean;
  agentVoices: Record<AgentRole, string>;
}

export type AgentConfig = {
  [key in AgentRole]: {
    // Names is now a function to allow dynamic naming based on mode (e.g., "Teacher" vs "Debater")
    names: (mode: SimulationMode, lang: Language) => string;
    systemInstruction: (topic: string, mode: SimulationMode, lang: Language) => string;
    color: string;
    avatar: string;
    voiceName: string; // Default voice
  };
};

import React, { useState } from "react";
import { Message, AgentRole, Language, SimulationMode } from "../types";
import { AGENT_CONFIG } from "../constants";
import { playAudioData } from "../services/ttsService";

interface ChatBubbleProps {
  message: Message;
  language: Language;
  // We need the mode to determine the correct display name (e.g., "Teacher" vs "Debater")
  // However, message doesn't store mode. We should pass it from parent or assume a default if missing.
  // For better architecture, let's pass it from the App.
  mode?: SimulationMode; 
}

export const ChatBubble: React.FC<ChatBubbleProps> = ({ message, language, mode = SimulationMode.DEBATE }) => {
  const config = AGENT_CONFIG[message.role];
  const isDirector = message.role === AgentRole.DIRECTOR;

  // Resolve the name function
  const displayName = config.names(mode, language);

  const [isPlaying, setIsPlaying] = useState(false);

  const handleReplay = async () => {
    if (!message.audioBase64 || isPlaying) return;
    setIsPlaying(true);
    await playAudioData(message.audioBase64);
    setIsPlaying(false);
  };

  return (
    <div
      className={`flex w-full mb-6 animate-fade-in ${
        isDirector ? "justify-center" : message.role === AgentRole.ACTOR_A ? "justify-start" : "justify-end"
      }`}
    >
      <div
        className={`flex max-w-[80%] md:max-w-[70%] flex-col ${
          message.role === AgentRole.ACTOR_B ? "items-end" : "items-start"
        }`}
      >
        <div className="flex items-center gap-2 mb-1">
          <span className="text-2xl filter drop-shadow-md">{config.avatar}</span>
          <span className={`text-xs font-bold uppercase tracking-wider ${
             isDirector ? "text-violet-400" : message.role === AgentRole.ACTOR_A ? "text-cyan-400" : "text-rose-400"
          }`}>
            {displayName}
          </span>
          {message.audioBase64 && (
            <button
              onClick={handleReplay}
              disabled={isPlaying}
              className={`ml-1 p-1 rounded-full hover:bg-slate-700/50 transition-colors ${
                 isPlaying ? "text-green-400 animate-pulse" : "text-slate-400 hover:text-white"
              }`}
              title="Replay Audio"
            >
               {isPlaying ? (
                 <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"></polygon><path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"></path></svg>
               ) : (
                 <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"></polygon><path d="M15.54 8.46a5 5 0 0 1 0 7.07"></path></svg>
               )}
            </button>
          )}
        </div>

        <div
          className={`relative p-4 rounded-2xl shadow-lg border border-opacity-10 backdrop-blur-sm ${
            isDirector
              ? "bg-violet-900/40 border-violet-500 text-center text-violet-100"
              : message.role === AgentRole.ACTOR_A
              ? "bg-cyan-900/30 border-cyan-500 text-cyan-50 rounded-tl-none"
              : "bg-rose-900/30 border-rose-500 text-rose-50 rounded-tr-none"
          }`}
        >
          <p className="whitespace-pre-wrap leading-relaxed text-sm md:text-base">
            {message.content}
          </p>
        </div>
      </div>
    </div>
  );
};

