import { useState, useRef, useEffect, useCallback } from "react";
import { Message, AgentRole, SimulationMode, SimulationState, Language } from "../types";
import { AGENT_CONFIG } from "../constants";
import { generateAgentResponse } from "../services/geminiService";
import { fetchTTS, playAudioData, initAudioContext, stopCurrentAudio } from "../services/ttsService";

export const useMultiAgentSimulation = () => {
  const [state, setState] = useState<SimulationState>({
    isPlaying: false,
    round: 0,
    maxRounds: 6,
    topic: "",
    mode: SimulationMode.DEBATE,
    language: 'en',
    messages: [],
    currentSpeaker: null,
    maxResponseLength: 80,
    isIntervening: false,
    isMuted: false, 
    agentVoices: {
        [AgentRole.DIRECTOR]: AGENT_CONFIG[AgentRole.DIRECTOR].voiceName,
        [AgentRole.ACTOR_A]: AGENT_CONFIG[AgentRole.ACTOR_A].voiceName,
        [AgentRole.ACTOR_B]: AGENT_CONFIG[AgentRole.ACTOR_B].voiceName,
    }
  });

  const stateRef = useRef(state);

  useEffect(() => {
    stateRef.current = state;
  }, [state]);

  // Modified to return the ID so we can update it later
  const addMessage = (role: AgentRole, content: string, audioBase64?: string): string => {
    const id = crypto.randomUUID();
    const newMessage: Message = {
      id,
      role,
      content,
      timestamp: Date.now(),
      audioBase64,
    };

    setState((prev) => ({
      ...prev,
      messages: [...prev.messages, newMessage],
    }));
    return id;
  };

  const updateMessageAudio = (id: string, audioBase64: string) => {
    setState((prev) => ({
      ...prev,
      messages: prev.messages.map((msg) => 
        msg.id === id ? { ...msg, audioBase64 } : msg
      ),
    }));
  };

  const processTurn = useCallback(async () => {
    const currentState = stateRef.current;

    if (!currentState.isPlaying) return;

    let nextSpeaker: AgentRole | null = null;
    const { messages, round, maxRounds, isIntervening } = currentState;
    let overrideInstruction = "";
    let willIncrementRound = false;

    if (isIntervening) {
       nextSpeaker = AgentRole.DIRECTOR;
       overrideInstruction = currentState.language === 'zh-TW'
         ? " 【重要指令】用戶要求你介入當前對話。請總結目前的衝突點，或引導演員進入新的討論方向。請保持專業且具引導性。"
         : " [URGENT] The user has requested you to intervene. Briefly summarize the conflict so far or steer the actors in a new direction. Be professional and guiding.";

       setState(prev => ({ ...prev, isIntervening: false }));
    } else if (messages.length === 0) {
      nextSpeaker = AgentRole.DIRECTOR;
    } else {
      const lastSpeaker = messages[messages.length - 1].role;

      if (round >= maxRounds) {
        if (lastSpeaker !== AgentRole.DIRECTOR) {
          nextSpeaker = AgentRole.DIRECTOR;
        } else {
          setState((prev) => ({ ...prev, isPlaying: false, currentSpeaker: null }));
          return;
        }
      } else {
        if (lastSpeaker === AgentRole.DIRECTOR) {
          nextSpeaker = AgentRole.ACTOR_A;
        } else if (lastSpeaker === AgentRole.ACTOR_A) {
          nextSpeaker = AgentRole.ACTOR_B;
        } else if (lastSpeaker === AgentRole.ACTOR_B) {
          nextSpeaker = AgentRole.DIRECTOR;
          willIncrementRound = true;
        }
      }
    }

    if (willIncrementRound) {
        setState((prev) => ({ ...prev, round: prev.round + 1 }));
    }

    if (nextSpeaker) {
      setState((prev) => ({ ...prev, currentSpeaker: nextSpeaker }));

      const config = AGENT_CONFIG[nextSpeaker];
      let systemInstruction = config.systemInstruction(currentState.topic, currentState.mode, currentState.language);

      const effectiveRound = willIncrementRound ? round + 1 : round;
      const isClosing = !isIntervening && nextSpeaker === AgentRole.DIRECTOR && effectiveRound >= maxRounds;

      if (isClosing) {
          systemInstruction += (currentState.language === 'zh-TW' ? " 這是會議的結束。請提供簡潔的總結並感謝參與者。" : " This is the end of the session. Provide a concise summary and thank the participants.");
      }

      if (overrideInstruction) {
          systemInstruction += " " + overrideInstruction;
      }

      // 1. Generate Text
      const response = await generateAgentResponse(
        nextSpeaker,
        systemInstruction,
        currentState.messages,
        currentState.topic,
        currentState.mode,
        currentState.language,
        currentState.maxResponseLength
      );

      // 2. IMMEDIATE UI UPDATE: Show text before fetching audio
      // This makes the app feel much faster as users can read while audio loads
      const messageId = addMessage(nextSpeaker, response, undefined);

      // 3. Generate Audio in background
      const selectedVoice = currentState.agentVoices[nextSpeaker];
      // Only fetch audio if not muted to save resources/time, OR fetch anyway for replay ability?
      // Fetching anyway ensures replay works later even if muted now.
      const audioData = await fetchTTS(response, selectedVoice);

      if (audioData) {
          updateMessageAudio(messageId, audioData);
      }

      // 4. Play Audio (Blocking if not muted)
      // Check stateRef again in case user paused/muted during generation
      if (stateRef.current.isPlaying && !stateRef.current.isMuted && audioData) {
          await playAudioData(audioData);
      }

      // 5. Queue next turn
      // Use a short delay if audio played (it already blocked), or longer if muted for readability
      const nextTurnDelay = stateRef.current.isMuted ? 2000 : 500;

      setTimeout(() => {
        processTurn();
      }, nextTurnDelay); 
    }
  }, []);

  const startSimulation = (
    topic: string, 
    mode: SimulationMode, 
    maxRounds: number = 6, 
    language: Language = 'en',
    maxResponseLength: number = 80
  ) => {
    // Initialize Audio Context on user interaction (Start button)
    initAudioContext();
    stopCurrentAudio(); // Ensure clean start

    setState(prev => ({
      isPlaying: true,
      round: 0,
      maxRounds,
      topic,
      mode,
      language,
      messages: [],
      currentSpeaker: null,
      maxResponseLength,
      isIntervening: false,
      isMuted: prev.isMuted, 
      agentVoices: prev.agentVoices 
    }));

    setTimeout(() => {
        processTurn();
    }, 100);
  };

  const stopSimulation = () => {
    stopCurrentAudio();
    setState((prev) => ({ ...prev, isPlaying: false, currentSpeaker: null }));
  };

  const loadState = (newState: SimulationState) => {
    stopCurrentAudio();
    // Force isPlaying to false to allow user to decide when to resume
    setState({ ...newState, isPlaying: false, currentSpeaker: null });
  };

  const togglePause = () => {
      // Immediate action based on current state
      if (state.isPlaying) {
          stopCurrentAudio();
      }

      setState(prev => {
          const nextIsPlaying = !prev.isPlaying;

          if (nextIsPlaying) {
             initAudioContext(); 
              setTimeout(() => {
                 processTurn();
              }, 100);
          }

          return { ...prev, isPlaying: nextIsPlaying };
      });
  };

  const toggleMute = () => {
      // Immediate action based on current state
      if (!state.isMuted) {
          stopCurrentAudio();
      }

      setState(prev => ({ ...prev, isMuted: !prev.isMuted }));
  };

  const triggerIntervention = () => {
      setState(prev => ({ ...prev, isIntervening: true }));
  };

  const resetSimulation = () => {
    stopCurrentAudio();
    setState((prev) => ({
      isPlaying: false,
      round: 0,
      maxRounds: 6,
      topic: "",
      mode: SimulationMode.DEBATE,
      language: prev.language, 
      messages: [],
      currentSpeaker: null,
      maxResponseLength: prev.maxResponseLength,
      isIntervening: false,
      isMuted: prev.isMuted,
      agentVoices: prev.agentVoices, 
    }));
  };

  const setAgentVoice = (role: AgentRole, voice: string) => {
    setState(prev => ({
        ...prev,
        agentVoices: {
            ...prev.agentVoices,
            [role]: voice
        }
    }));
  };

  return {
    state,
    startSimulation,
    stopSimulation,
    resetSimulation,
    togglePause,
    triggerIntervention,
    toggleMute,
    setAgentVoice,
    loadState,
  };
};

import React, { useState, useRef, useEffect } from "react";
import { useMultiAgentSimulation } from "./hooks/useMultiAgentSimulation";
import { SimulationMode, AgentRole, Language } from "./types";
import { ChatBubble } from "./components/ChatBubble";
import { AGENT_CONFIG, TRANSLATIONS, RANDOM_TOPICS, AVAILABLE_VOICES } from "./constants";

const MAX_TOPIC_LENGTH = 100;

const App: React.FC = () => {
  const { 
    state, 
    startSimulation, 
    stopSimulation, 
    resetSimulation, 
    togglePause, 
    triggerIntervention, 
    toggleMute,
    setAgentVoice,
    loadState
  } = useMultiAgentSimulation();

  const [inputTopic, setInputTopic] = useState("");
  const [numRounds, setNumRounds] = useState(6);
  const [selectedMode, setSelectedMode] = useState<SimulationMode>(SimulationMode.DEBATE);
  const [language, setLanguage] = useState<Language>('en'); 
  // Use string | number to allow empty input while typing
  const [maxLen, setMaxLen] = useState<number | string>(80);
  const scrollRef = useRef<HTMLDivElement>(null);

  const t = TRANSLATIONS[language]; 

  // Auto-scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollIntoView({ behavior: "smooth" });
    }
  }, [state.messages, state.currentSpeaker]);

  // Update default max length when language changes
  useEffect(() => {
    if (language === 'zh-TW') {
        setMaxLen(150);
    } else {
        setMaxLen(80);
    }
  }, [language]);

  const handleStart = () => {
    if (!inputTopic.trim()) return;
    // Ensure maxLen is a valid number before starting
    const finalLen = Number(maxLen) || (language === 'zh-TW' ? 150 : 80);
    startSimulation(inputTopic, selectedMode, numRounds || 6, language, finalLen);
  };

  const toggleLanguage = () => {
      setLanguage(prev => prev === 'en' ? 'zh-TW' : 'en');
  };

  const handleRandomTopic = () => {
      const topics = RANDOM_TOPICS[language][selectedMode];
      const randomTopic = topics[Math.floor(Math.random() * topics.length)];
      setInputTopic(randomTopic);
  };

  const handleMaxLenBlur = () => {
    let val = Number(maxLen);
    if (!val || val < 10) val = 10;
    if (val > 1000) val = 1000;
    setMaxLen(val);
  };

  const handleSaveSession = () => {
      try {
          // Deep clone state to avoid mutating original
          const stateToSave = JSON.parse(JSON.stringify(state));

          // Strip audio data to save space in localStorage (5MB limit)
          stateToSave.messages.forEach((msg: any) => {
              delete msg.audioBase64;
          });

          const sessionData = {
              simulationState: stateToSave,
              uiState: {
                  inputTopic: state.topic || inputTopic,
                  numRounds: state.maxRounds || numRounds,
                  selectedMode: state.mode || selectedMode,
                  language: state.language || language,
                  maxLen: state.maxResponseLength || maxLen
              }
          };

          localStorage.setItem('gemini_agent_session', JSON.stringify(sessionData));
          alert(t.sessionSaved);
      } catch (e) {
          console.error("Save failed", e);
          alert("Failed to save session (possibly too large).");
      }
  };

  const handleLoadSession = () => {
      try {
          const saved = localStorage.getItem('gemini_agent_session');
          if (!saved) {
              alert(t.noSavedSession);
              return;
          }

          const data = JSON.parse(saved);

          if (data.uiState) {
              setInputTopic(data.uiState.inputTopic || "");
              setNumRounds(data.uiState.numRounds || 6);
              setSelectedMode(data.uiState.selectedMode || SimulationMode.DEBATE);
              setLanguage(data.uiState.language || 'en');
              setMaxLen(data.uiState.maxLen || 80);
          }

          if (data.simulationState) {
              loadState(data.simulationState);
          }
      } catch (e) {
          console.error("Load failed", e);
          alert(t.loadError);
      }
  };

  return (
    <div className="min-h-screen flex flex-col items-center bg-slate-900 text-slate-100 font-sans selection:bg-violet-500 selection:text-white">
      {/* Header */}
      <header className="w-full max-w-4xl p-6 border-b border-slate-800 bg-slate-900/80 backdrop-blur sticky top-0 z-10 flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-gradient-to-br from-violet-500 to-fuchsia-500 flex items-center justify-center text-xl shadow-lg shadow-violet-500/20">
            🤖
          </div>
          <div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-violet-400 to-fuchsia-400">
              {t.appTitle}
            </h1>
            <p className="text-xs text-slate-400">{t.poweredBy}</p>
          </div>
        </div>

        <div className="flex items-center gap-4 flex-wrap justify-end">
            {/* Save / Load */}
            <div className="flex gap-2">
                <button 
                    onClick={handleSaveSession}
                    className="p-2 text-xs rounded-lg border border-slate-700 bg-slate-800 hover:bg-slate-700 transition-colors text-slate-300"
                    title={t.saveSession}
                >
                    💾 {t.saveSession}
                </button>
                <button 
                    onClick={handleLoadSession}
                    className="p-2 text-xs rounded-lg border border-slate-700 bg-slate-800 hover:bg-slate-700 transition-colors text-slate-300"
                    title={t.loadSession}
                >
                    📂 {t.loadSession}
                </button>
            </div>

            <div className="h-6 w-px bg-slate-700 mx-1 hidden md:block"></div>

            {/* Mute Toggle */}
            <button
              onClick={toggleMute}
              className="p-2 rounded-lg text-slate-400 hover:text-slate-100 hover:bg-slate-800 transition-colors"
              title={state.isMuted ? t.unmute : t.mute}
            >
               {state.isMuted ? "🔇" : "🔊"}
            </button>

            {/* Language Toggle */}
            <button 
                onClick={toggleLanguage}
                className="px-3 py-1 rounded-lg border border-slate-600 bg-slate-800 hover:bg-slate-700 text-sm font-medium transition-colors"
            >
                {language === 'en' ? '中文' : 'English'}
            </button>

            {/* Status Indicator */}
            <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-slate-800 border border-slate-700">
                <div className={`w-2 h-2 rounded-full ${state.isPlaying ? 'bg-green-500 animate-pulse' : 'bg-slate-500'}`} />
                <span className="text-xs font-medium text-slate-300">
                    {state.isPlaying ? t.sessionActive : (state.messages.length > 0 ? t.pause : t.ready)}
                </span>
            </div>
        </div>
      </header>

      {/* Main Stage */}
      <main className="flex-1 w-full max-w-4xl p-4 md:p-6 flex flex-col gap-6">

        {/* Controls (Only visible when not playing or empty) */}
        {!state.isPlaying && state.messages.length === 0 && (
          <div className="w-full bg-slate-800/50 p-6 md:p-8 rounded-3xl border border-slate-700 shadow-xl animate-fade-in space-y-8">
            <h2 className="text-2xl font-bold text-center">{t.setStage}</h2>

            {/* Mode Selection */}
            <div>
              <label className="block text-sm font-medium text-slate-400 mb-2">{t.selectFormat}</label>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <button
                  onClick={() => setSelectedMode(SimulationMode.DEBATE)}
                  className={`p-4 rounded-xl border-2 transition-all duration-200 flex flex-col items-center gap-2 ${
                    selectedMode === SimulationMode.DEBATE
                      ? "border-violet-500 bg-violet-500/10 text-violet-100"
                      : "border-slate-700 bg-slate-800 text-slate-400 hover:border-slate-600"
                  }`}
                >
                  <span className="text-2xl">⚖️</span>
                  <span className="font-bold">{t.debate}</span>
                  <span className="text-xs opacity-70">{t.debateDesc}</span>
                </button>
                <button
                  onClick={() => setSelectedMode(SimulationMode.THEATER)}
                  className={`p-4 rounded-xl border-2 transition-all duration-200 flex flex-col items-center gap-2 ${
                    selectedMode === SimulationMode.THEATER
                      ? "border-fuchsia-500 bg-fuchsia-500/10 text-fuchsia-100"
                      : "border-slate-700 bg-slate-800 text-slate-400 hover:border-slate-600"
                  }`}
                >
                  <span className="text-2xl">🎭</span>
                  <span className="font-bold">{t.theater}</span>
                  <span className="text-xs opacity-70">{t.theaterDesc}</span>
                </button>
                <button
                  onClick={() => setSelectedMode(SimulationMode.EDUCATION)}
                  className={`p-4 rounded-xl border-2 transition-all duration-200 flex flex-col items-center gap-2 ${
                    selectedMode === SimulationMode.EDUCATION
                      ? "border-emerald-500 bg-emerald-500/10 text-emerald-100"
                      : "border-slate-700 bg-slate-800 text-slate-400 hover:border-slate-600"
                  }`}
                >
                  <span className="text-2xl">🎓</span>
                  <span className="font-bold">{t.education}</span>
                  <span className="text-xs opacity-70">{t.educationDesc}</span>
                </button>
              </div>
            </div>

            {/* Voice Cast Settings */}
            <div>
               <label className="block text-sm font-medium text-slate-400 mb-3">{t.voiceCast}</label>
               <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  {[AgentRole.DIRECTOR, AgentRole.ACTOR_A, AgentRole.ACTOR_B].map(role => {
                    const currentVoice = state.agentVoices[role];
                    const config = AGENT_CONFIG[role];
                    return (
                      <div key={role} className="flex flex-col gap-1">
                        <div className="flex items-center gap-2 text-xs font-bold uppercase tracking-wider mb-1" style={{ color: role === AgentRole.DIRECTOR ? '#a78bfa' : role === AgentRole.ACTOR_A ? '#22d3ee' : '#fb7185' }}>
                           <span>{config.avatar}</span>
                           <span>{config.names(selectedMode, language)}</span>
                        </div>
                        <select
                          value={currentVoice}
                          onChange={(e) => setAgentVoice(role, e.target.value)}
                          className="w-full bg-slate-900 border border-slate-700 rounded-lg p-2 text-sm text-slate-200 focus:outline-none focus:ring-1 focus:ring-violet-500"
                        >
                          {AVAILABLE_VOICES.map((v) => (
                            <option key={v.id} value={v.id}>
                              {v.label}
                            </option>
                          ))}
                        </select>
                      </div>
                    );
                  })}
               </div>
            </div>

            {/* Inputs: Topic, Rounds, Length */}
            <div className="flex flex-col md:flex-row gap-4">
              <div className="flex-grow">
                <label className="block text-sm font-medium text-slate-400 mb-2 flex items-center justify-between">
                    {t.topicLabel}
                    <button 
                      onClick={handleRandomTopic}
                      className="text-violet-400 hover:text-violet-300 text-xs flex items-center gap-1 transition-colors"
                    >
                       <span>🎲</span> {t.randomTopic}
                    </button>
                </label>
                <div className="relative">
                  <input
                    type="text"
                    maxLength={MAX_TOPIC_LENGTH}
                    value={inputTopic}
                    onChange={(e) => setInputTopic(e.target.value)}
                    placeholder={
                      selectedMode === SimulationMode.DEBATE
                        ? t.topicPlaceholderDebate
                        : selectedMode === SimulationMode.THEATER
                        ? t.topicPlaceholderTheater
                        : t.topicPlaceholderEducation
                    }
                    className="w-full bg-slate-900 border border-slate-700 rounded-xl p-4 pr-16 text-slate-100 focus:outline-none focus:ring-2 focus:ring-violet-500 transition-all placeholder-slate-600"
                    onKeyDown={(e) => e.key === 'Enter' && handleStart()}
                  />
                  <div className={`absolute right-4 top-1/2 -translate-y-1/2 text-xs font-mono ${
                      inputTopic.length >= MAX_TOPIC_LENGTH ? 'text-red-400' : 'text-slate-500'
                  }`}>
                    {inputTopic.length}/{MAX_TOPIC_LENGTH}
                  </div>
                </div>
              </div>

              <div className="flex gap-4">
                  <div className="w-24">
                     <label className="block text-sm font-medium text-slate-400 mb-2">{t.roundsLabel}</label>
                     <input
                        type="number"
                        min={1}
                        max={20}
                        value={numRounds}
                        onChange={(e) => setNumRounds(parseInt(e.target.value) || 0)}
                        className="w-full bg-slate-900 border border-slate-700 rounded-xl p-4 text-center text-slate-100 focus:outline-none focus:ring-2 focus:ring-violet-500 transition-all"
                     />
                  </div>

                   <div className="w-32">
                     <label className="block text-sm font-medium text-slate-400 mb-2">{t.maxLengthLabel}</label>
                     <div className="relative">
                         <input
                            type="number"
                            min={10}
                            max={500}
                            step={10}
                            value={maxLen}
                            onChange={(e) => setMaxLen(e.target.value)}
                            onBlur={handleMaxLenBlur}
                            className="w-full bg-slate-900 border border-slate-700 rounded-xl p-4 text-center text-slate-100 focus:outline-none focus:ring-2 focus:ring-violet-500 transition-all"
                         />
                         <span className="absolute right-3 top-1/2 -translate-y-1/2 text-xs text-slate-500 pointer-events-none">
                             {t.wordUnit}
                         </span>
                     </div>
                  </div>
              </div>
            </div>

            <button
              onClick={handleStart}
              disabled={!inputTopic.trim()}
              className="w-full py-4 rounded-xl font-bold text-lg bg-gradient-to-r from-violet-600 to-fuchsia-600 hover:from-violet-500 hover:to-fuchsia-500 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-lg shadow-violet-900/50 flex items-center justify-center gap-2"
            >
              <span>🎬</span>
              <span>{t.action}</span>
            </button>
          </div>
        )}

        {/* Script Display */}
        {(state.messages.length > 0 || state.isPlaying) && (
           <div className="flex-1 min-h-[500px] flex flex-col relative">
              <div className="flex-1 space-y-2 pb-24">
                  {state.messages.map((msg) => (
                    <ChatBubble key={msg.id} message={msg} language={state.language} mode={state.mode} />
                  ))}

                  {/* Loading / Typing Indicator */}
                  {state.isPlaying && state.currentSpeaker && (
                     <div className="flex w-full justify-center animate-pulse">
                        <div className={`px-4 py-2 rounded-full text-xs font-bold border ${
                            state.currentSpeaker === AgentRole.DIRECTOR ? 'border-violet-500 text-violet-400 bg-violet-900/20' :
                            state.currentSpeaker === AgentRole.ACTOR_A ? 'border-cyan-500 text-cyan-400 bg-cyan-900/20' :
                            'border-rose-500 text-rose-400 bg-rose-900/20'
                        }`}>
                           {AGENT_CONFIG[state.currentSpeaker].avatar} {AGENT_CONFIG[state.currentSpeaker].names(state.mode, state.language)} {t.thinking}
                        </div>
                     </div>
                  )}
                  <div ref={scrollRef} />
              </div>

              {/* Floating Action Bar */}
              <div className="fixed bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-3 bg-slate-900/95 backdrop-blur-md border border-slate-700/50 p-2 pl-3 pr-2 rounded-2xl shadow-2xl z-50 ring-1 ring-white/10">

                 {/* Intervene Button */}
                 <button
                   onClick={() => triggerIntervention()}
                   disabled={!state.isPlaying || state.isIntervening}
                   title={t.interveneTooltip}
                   className={`flex flex-col items-center justify-center w-12 h-12 rounded-xl transition-all ${
                     state.isIntervening 
                      ? "bg-violet-500 text-white animate-pulse" 
                      : "bg-slate-800 hover:bg-violet-600/20 text-slate-300 hover:text-violet-300 border border-slate-700 hover:border-violet-500/50"
                   } disabled:opacity-30 disabled:cursor-not-allowed`}
                 >
                   <span className="text-xl">📢</span>
                 </button>

                 <div className="h-8 w-px bg-slate-700 mx-1"></div>

                 {/* Pause / Resume */}
                 <button 
                    onClick={togglePause}
                    className={`flex items-center gap-2 px-6 h-12 rounded-xl font-bold transition-all ${
                       state.isPlaying 
                         ? "bg-amber-500/10 hover:bg-amber-500/20 text-amber-400 border border-amber-500/30 hover:border-amber-500" 
                         : "bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400 border border-emerald-500/30 hover:border-emerald-500"
                    }`}
                 >
                    <span className="text-xl">{state.isPlaying ? "⏸" : "▶️"}</span>
                    <span>{state.isPlaying ? t.pause : t.resume}</span>
                 </button>

                 {/* Reset / New Scene */}
                 {!state.isPlaying && (
                     <button 
                        onClick={resetSimulation}
                        className="flex items-center gap-2 px-4 h-12 bg-slate-800 hover:bg-slate-700 text-slate-300 border border-slate-700 hover:border-slate-600 rounded-xl transition-colors font-semibold"
                    >
                        <span>🔄</span>
                        <span className="hidden sm:inline">{t.newScene}</span>
                    </button>
                 )}
              </div>
           </div>
        )}
      </main>
    </div>
  );
};

export default App;

import { useState, useRef, useEffect, useCallback } from "react";
import { Message, AgentRole, SimulationMode, SimulationState, Language } from "../types";
import { AGENT_CONFIG } from "../constants";
import { generateAgentResponse } from "../services/geminiService";
import { fetchTTS, playAudioData, initAudioContext, stopCurrentAudio } from "../services/ttsService";

export const useMultiAgentSimulation = () => {
  const [state, setState] = useState<SimulationState>({
    isPlaying: false,
    round: 0,
    maxRounds: 6,
    topic: "",
    mode: SimulationMode.DEBATE,
    language: 'en',
    messages: [],
    currentSpeaker: null,
    maxResponseLength: 80,
    isIntervening: false,
    isMuted: false, 
    agentVoices: {
        [AgentRole.DIRECTOR]: AGENT_CONFIG[AgentRole.DIRECTOR].voiceName,
        [AgentRole.ACTOR_A]: AGENT_CONFIG[AgentRole.ACTOR_A].voiceName,
        [AgentRole.ACTOR_B]: AGENT_CONFIG[AgentRole.ACTOR_B].voiceName,
    }
  });

  const stateRef = useRef(state);

  useEffect(() => {
    stateRef.current = state;
  }, [state]);

  // Modified to return the ID so we can update it later
  const addMessage = (role: AgentRole, content: string, audioBase64?: string): string => {
    const id = crypto.randomUUID();
    const newMessage: Message = {
      id,
      role,
      content,
      timestamp: Date.now(),
      audioBase64,
    };

    setState((prev) => ({
      ...prev,
      messages: [...prev.messages, newMessage],
    }));
    return id;
  };

  const updateMessageAudio = (id: string, audioBase64: string) => {
    setState((prev) => ({
      ...prev,
      messages: prev.messages.map((msg) => 
        msg.id === id ? { ...msg, audioBase64 } : msg
      ),
    }));
  };

  const processTurn = useCallback(async () => {
    const currentState = stateRef.current;

    if (!currentState.isPlaying) return;

    let nextSpeaker: AgentRole | null = null;
    const { messages, round, maxRounds, isIntervening } = currentState;
    let overrideInstruction = "";
    let willIncrementRound = false;

    if (isIntervening) {
       nextSpeaker = AgentRole.DIRECTOR;
       overrideInstruction = currentState.language === 'zh-TW'
         ? " 【重要指令】用戶要求你介入當前對話。請總結目前的衝突點，或引導演員進入新的討論方向。請保持專業且具引導性。"
         : " [URGENT] The user has requested you to intervene. Briefly summarize the conflict so far or steer the actors in a new direction. Be professional and guiding.";

       setState(prev => ({ ...prev, isIntervening: false }));
    } else if (messages.length === 0) {
      nextSpeaker = AgentRole.DIRECTOR;
    } else {
      const lastSpeaker = messages[messages.length - 1].role;

      if (round >= maxRounds) {
        if (lastSpeaker !== AgentRole.DIRECTOR) {
          nextSpeaker = AgentRole.DIRECTOR;
        } else {
          setState((prev) => ({ ...prev, isPlaying: false, currentSpeaker: null }));
          return;
        }
      } else {
        if (lastSpeaker === AgentRole.DIRECTOR) {
          nextSpeaker = AgentRole.ACTOR_A;
        } else if (lastSpeaker === AgentRole.ACTOR_A) {
          nextSpeaker = AgentRole.ACTOR_B;
        } else if (lastSpeaker === AgentRole.ACTOR_B) {
          nextSpeaker = AgentRole.DIRECTOR;
          willIncrementRound = true;
        }
      }
    }

    if (willIncrementRound) {
        setState((prev) => ({ ...prev, round: prev.round + 1 }));
    }

    if (nextSpeaker) {
      setState((prev) => ({ ...prev, currentSpeaker: nextSpeaker }));

      const config = AGENT_CONFIG[nextSpeaker];
      let systemInstruction = config.systemInstruction(currentState.topic, currentState.mode, currentState.language);

      const effectiveRound = willIncrementRound ? round + 1 : round;
      const isClosing = !isIntervening && nextSpeaker === AgentRole.DIRECTOR && effectiveRound >= maxRounds;

      if (isClosing) {
          systemInstruction += (currentState.language === 'zh-TW' ? " 這是會議的結束。請提供簡潔的總結並感謝參與者。" : " This is the end of the session. Provide a concise summary and thank the participants.");
      }

      if (overrideInstruction) {
          systemInstruction += " " + overrideInstruction;
      }

      // 1. Generate Text
      const response = await generateAgentResponse(
        nextSpeaker,
        systemInstruction,
        currentState.messages,
        currentState.topic,
        currentState.mode,
        currentState.language,
        currentState.maxResponseLength
      );

      // 2. IMMEDIATE UI UPDATE: Show text before fetching audio
      // This makes the app feel much faster as users can read while audio loads
      const messageId = addMessage(nextSpeaker, response, undefined);

      // 3. Generate Audio in background
      const selectedVoice = currentState.agentVoices[nextSpeaker];
      // Only fetch audio if not muted to save resources/time, OR fetch anyway for replay ability?
      // Fetching anyway ensures replay works later even if muted now.
      const audioData = await fetchTTS(response, selectedVoice);

      if (audioData) {
          updateMessageAudio(messageId, audioData);
      }

      // 4. Play Audio (Blocking if not muted)
      // Check stateRef again in case user paused/muted during generation
      if (stateRef.current.isPlaying && !stateRef.current.isMuted && audioData) {
          await playAudioData(audioData);
      }

      // 5. Queue next turn
      // Use a short delay if audio played (it already blocked), or longer if muted for readability
      const nextTurnDelay = stateRef.current.isMuted ? 2000 : 500;

      setTimeout(() => {
        processTurn();
      }, nextTurnDelay); 
    }
  }, []);

  const startSimulation = (
    topic: string, 
    mode: SimulationMode, 
    maxRounds: number = 6, 
    language: Language = 'en',
    maxResponseLength: number = 80
  ) => {
    // Initialize Audio Context on user interaction (Start button)
    initAudioContext();
    stopCurrentAudio(); // Ensure clean start

    setState(prev => ({
      isPlaying: true,
      round: 0,
      maxRounds,
      topic,
      mode,
      language,
      messages: [],
      currentSpeaker: null,
      maxResponseLength,
      isIntervening: false,
      isMuted: prev.isMuted, 
      agentVoices: prev.agentVoices 
    }));

    setTimeout(() => {
        processTurn();
    }, 100);
  };

  const stopSimulation = () => {
    stopCurrentAudio();
    setState((prev) => ({ ...prev, isPlaying: false, currentSpeaker: null }));
  };

  const loadState = (newState: SimulationState) => {
    stopCurrentAudio();
    // Force isPlaying to false to allow user to decide when to resume
    setState({ ...newState, isPlaying: false, currentSpeaker: null });
  };

  const togglePause = () => {
      const currentState = stateRef.current;

      // Immediate action based on current state
      if (currentState.isPlaying) {
          stopCurrentAudio();
      }

      const nextIsPlaying = !currentState.isPlaying;

      // 1. Update React State
      setState(prev => ({ ...prev, isPlaying: nextIsPlaying }));

      // 2. CRITICAL FIX: Manually update the Ref immediately.
      // waiting for the useEffect to fire (after render) is too slow and causes a race condition
      // where processTurn sees isPlaying=false and stops immediately.
      stateRef.current = { ...currentState, isPlaying: nextIsPlaying };

      if (nextIsPlaying) {
         initAudioContext(); 
         // Use a small timeout to let the UI update the button state, 
         // but the Ref is already ready for logic.
          setTimeout(() => {
             processTurn();
          }, 50);
      }
  };

  const toggleMute = () => {
      // Immediate action based on current state
      if (!state.isMuted) {
          stopCurrentAudio();
      }

      setState(prev => ({ ...prev, isMuted: !prev.isMuted }));
  };

  const triggerIntervention = () => {
      setState(prev => ({ ...prev, isIntervening: true }));
  };

  const resetSimulation = () => {
    stopCurrentAudio();
    setState((prev) => ({
      isPlaying: false,
      round: 0,
      maxRounds: 6,
      topic: "",
      mode: SimulationMode.DEBATE,
      language: prev.language, 
      messages: [],
      currentSpeaker: null,
      maxResponseLength: prev.maxResponseLength,
      isIntervening: false,
      isMuted: prev.isMuted,
      agentVoices: prev.agentVoices, 
    }));
  };

  const setAgentVoice = (role: AgentRole, voice: string) => {
    setState(prev => ({
        ...prev,
        agentVoices: {
            ...prev.agentVoices,
            [role]: voice
        }
    }));
  };

  return {
    state,
    startSimulation,
    stopSimulation,
    resetSimulation,
    togglePause,
    triggerIntervention,
    toggleMute,
    setAgentVoice,
    loadState,
  };
};

import React, { useState, useRef, useEffect } from "react";
import { useMultiAgentSimulation } from "./hooks/useMultiAgentSimulation";
import { SimulationMode, AgentRole, Language } from "./types";
import { ChatBubble } from "./components/ChatBubble";
import { AGENT_CONFIG, TRANSLATIONS, RANDOM_TOPICS, AVAILABLE_VOICES } from "./constants";

const MAX_TOPIC_LENGTH = 100;

const App: React.FC = () => {
  const { 
    state, 
    startSimulation, 
    stopSimulation, 
    resetSimulation, 
    togglePause, 
    triggerIntervention, 
    toggleMute,
    setAgentVoice,
    loadState
  } = useMultiAgentSimulation();

  const [inputTopic, setInputTopic] = useState("");
  const [numRounds, setNumRounds] = useState(6);
  const [selectedMode, setSelectedMode] = useState<SimulationMode>(SimulationMode.DEBATE);
  const [language, setLanguage] = useState<Language>('en'); 
  // Use string | number to allow empty input while typing
  const [maxLen, setMaxLen] = useState<number | string>(80);
  const scrollRef = useRef<HTMLDivElement>(null);

  const t = TRANSLATIONS[language]; 

  // Auto-scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollIntoView({ behavior: "smooth" });
    }
  }, [state.messages, state.currentSpeaker]);

  // Update default max length when language changes
  useEffect(() => {
    if (language === 'zh-TW') {
        setMaxLen(150);
    } else {
        setMaxLen(80);
    }
  }, [language]);

  const handleStart = () => {
    if (!inputTopic.trim()) return;
    // Ensure maxLen is a valid number before starting
    const finalLen = Number(maxLen) || (language === 'zh-TW' ? 150 : 80);
    startSimulation(inputTopic, selectedMode, numRounds || 6, language, finalLen);
  };

  const toggleLanguage = () => {
      setLanguage(prev => prev === 'en' ? 'zh-TW' : 'en');
  };

  const handleRandomTopic = () => {
      const topics = RANDOM_TOPICS[language][selectedMode];
      const randomTopic = topics[Math.floor(Math.random() * topics.length)];
      setInputTopic(randomTopic);
  };

  const handleMaxLenBlur = () => {
    let val = Number(maxLen);
    if (!val || val < 10) val = 10;
    if (val > 1000) val = 1000;
    setMaxLen(val);
  };

  const handleSaveSession = () => {
      try {
          // Deep clone state to avoid mutating original
          const stateToSave = JSON.parse(JSON.stringify(state));

          // Strip audio data to save space in localStorage (5MB limit)
          stateToSave.messages.forEach((msg: any) => {
              delete msg.audioBase64;
          });

          const sessionData = {
              simulationState: stateToSave,
              uiState: {
                  inputTopic: state.topic || inputTopic,
                  numRounds: state.maxRounds || numRounds,
                  selectedMode: state.mode || selectedMode,
                  language: state.language || language,
                  maxLen: state.maxResponseLength || maxLen
              }
          };

          localStorage.setItem('gemini_agent_session', JSON.stringify(sessionData));
          alert(t.sessionSaved);
      } catch (e) {
          console.error("Save failed", e);
          alert("Failed to save session (possibly too large).");
      }
  };

  const handleLoadSession = () => {
      try {
          const saved = localStorage.getItem('gemini_agent_session');
          if (!saved) {
              alert(t.noSavedSession);
              return;
          }

          const data = JSON.parse(saved);

          if (data.uiState) {
              setInputTopic(data.uiState.inputTopic || "");
              setNumRounds(data.uiState.numRounds || 6);
              setSelectedMode(data.uiState.selectedMode || SimulationMode.DEBATE);
              setLanguage(data.uiState.language || 'en');
              setMaxLen(data.uiState.maxLen || 80);
          }

          if (data.simulationState) {
              loadState(data.simulationState);
          }
      } catch (e) {
          console.error("Load failed", e);
          alert(t.loadError);
      }
  };

  return (
    <div className="min-h-screen flex flex-col items-center bg-slate-50 text-slate-900 font-sans selection:bg-violet-200 selection:text-violet-900">
      {/* Header */}
      <header className="w-full max-w-5xl p-6 border-b border-slate-200 bg-white/90 backdrop-blur sticky top-0 z-10 flex flex-col md:flex-row justify-between items-center gap-4 shadow-sm">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-full bg-gradient-to-br from-violet-500 to-fuchsia-500 flex items-center justify-center text-2xl shadow-lg shadow-violet-500/20 text-white">
            🤖
          </div>
          <div>
            <h1 className="text-2xl md:text-3xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-violet-600 to-fuchsia-600">
              {t.appTitle}
            </h1>
            <p className="text-sm text-slate-500 font-medium">{t.poweredBy}</p>
          </div>
        </div>

        <div className="flex items-center gap-4 flex-wrap justify-end">
            {/* Save / Load */}
            <div className="flex gap-2">
                <button 
                    onClick={handleSaveSession}
                    className="px-3 py-2 text-sm md:text-base rounded-xl border border-slate-300 bg-white hover:bg-slate-50 transition-colors text-slate-700 font-medium shadow-sm"
                    title={t.saveSession}
                >
                    💾 {t.saveSession}
                </button>
                <button 
                    onClick={handleLoadSession}
                    className="px-3 py-2 text-sm md:text-base rounded-xl border border-slate-300 bg-white hover:bg-slate-50 transition-colors text-slate-700 font-medium shadow-sm"
                    title={t.loadSession}
                >
                    📂 {t.loadSession}
                </button>
            </div>

            <div className="h-8 w-px bg-slate-300 mx-1 hidden md:block"></div>

            {/* Mute Toggle */}
            <button
              onClick={toggleMute}
              className="p-3 rounded-xl text-slate-600 hover:text-slate-900 hover:bg-slate-100 transition-colors border border-transparent hover:border-slate-200"
              title={state.isMuted ? t.unmute : t.mute}
            >
               <span className="text-xl">{state.isMuted ? "🔇" : "🔊"}</span>
            </button>

            {/* Language Toggle */}
            <button 
                onClick={toggleLanguage}
                className="px-4 py-2 rounded-xl border border-slate-300 bg-white hover:bg-slate-50 text-base font-bold text-slate-700 transition-colors shadow-sm"
            >
                {language === 'en' ? '中文' : 'English'}
            </button>

            {/* Status Indicator */}
            <div className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-100 border border-slate-200">
                <div className={`w-3 h-3 rounded-full ${state.isPlaying ? 'bg-green-500 animate-pulse' : 'bg-slate-400'}`} />
                <span className="text-sm font-bold text-slate-600">
                    {state.isPlaying ? t.sessionActive : (state.messages.length > 0 ? t.pause : t.ready)}
                </span>
            </div>
        </div>
      </header>

      {/* Main Stage */}
      <main className="flex-1 w-full max-w-5xl p-4 md:p-8 flex flex-col gap-8">

        {/* Controls (Only visible when not playing or empty) */}
        {!state.isPlaying && state.messages.length === 0 && (
          <div className="w-full bg-white p-6 md:p-10 rounded-3xl border border-slate-200 shadow-xl animate-fade-in space-y-10">
            <h2 className="text-3xl md:text-4xl font-bold text-center text-slate-800">{t.setStage}</h2>

            {/* Mode Selection */}
            <div>
              <label className="block text-lg font-bold text-slate-700 mb-4">{t.selectFormat}</label>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <button
                  onClick={() => setSelectedMode(SimulationMode.DEBATE)}
                  className={`p-6 rounded-2xl border-2 transition-all duration-200 flex flex-col items-center gap-3 ${
                    selectedMode === SimulationMode.DEBATE
                      ? "border-violet-500 bg-violet-50 text-violet-900 shadow-md"
                      : "border-slate-200 bg-slate-50 text-slate-500 hover:border-slate-400 hover:bg-white"
                  }`}
                >
                  <span className="text-4xl">⚖️</span>
                  <span className="text-xl font-bold">{t.debate}</span>
                  <span className="text-sm opacity-80">{t.debateDesc}</span>
                </button>
                <button
                  onClick={() => setSelectedMode(SimulationMode.THEATER)}
                  className={`p-6 rounded-2xl border-2 transition-all duration-200 flex flex-col items-center gap-3 ${
                    selectedMode === SimulationMode.THEATER
                      ? "border-fuchsia-500 bg-fuchsia-50 text-fuchsia-900 shadow-md"
                      : "border-slate-200 bg-slate-50 text-slate-500 hover:border-slate-400 hover:bg-white"
                  }`}
                >
                  <span className="text-4xl">🎭</span>
                  <span className="text-xl font-bold">{t.theater}</span>
                  <span className="text-sm opacity-80">{t.theaterDesc}</span>
                </button>
                <button
                  onClick={() => setSelectedMode(SimulationMode.EDUCATION)}
                  className={`p-6 rounded-2xl border-2 transition-all duration-200 flex flex-col items-center gap-3 ${
                    selectedMode === SimulationMode.EDUCATION
                      ? "border-emerald-500 bg-emerald-50 text-emerald-900 shadow-md"
                      : "border-slate-200 bg-slate-50 text-slate-500 hover:border-slate-400 hover:bg-white"
                  }`}
                >
                  <span className="text-4xl">🎓</span>
                  <span className="text-xl font-bold">{t.education}</span>
                  <span className="text-sm opacity-80">{t.educationDesc}</span>
                </button>
              </div>
            </div>

            {/* Voice Cast Settings */}
            <div>
               <label className="block text-lg font-bold text-slate-700 mb-4">{t.voiceCast}</label>
               <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  {[AgentRole.DIRECTOR, AgentRole.ACTOR_A, AgentRole.ACTOR_B].map(role => {
                    const currentVoice = state.agentVoices[role];
                    const config = AGENT_CONFIG[role];
                    const roleColor = role === AgentRole.DIRECTOR ? 'text-violet-600' : role === AgentRole.ACTOR_A ? 'text-cyan-600' : 'text-rose-600';
                    return (
                      <div key={role} className="flex flex-col gap-2">
                        <div className={`flex items-center gap-2 text-sm font-bold uppercase tracking-wider ${roleColor}`}>
                           <span className="text-xl">{config.avatar}</span>
                           <span>{config.names(selectedMode, language)}</span>
                        </div>
                        <select
                          value={currentVoice}
                          onChange={(e) => setAgentVoice(role, e.target.value)}
                          className="w-full bg-slate-50 border border-slate-300 rounded-xl p-3 text-base text-slate-800 focus:outline-none focus:ring-2 focus:ring-violet-500 shadow-sm"
                        >
                          {AVAILABLE_VOICES.map((v) => (
                            <option key={v.id} value={v.id}>
                              {v.label}
                            </option>
                          ))}
                        </select>
                      </div>
                    );
                  })}
               </div>
            </div>

            {/* Inputs: Topic, Rounds, Length */}
            <div className="flex flex-col md:flex-row gap-6">
              <div className="flex-grow">
                <label className="block text-lg font-bold text-slate-700 mb-3 flex items-center justify-between">
                    {t.topicLabel}
                    <button 
                      onClick={handleRandomTopic}
                      className="text-violet-600 hover:text-violet-800 text-sm font-bold flex items-center gap-1 transition-colors bg-violet-50 px-3 py-1 rounded-lg hover:bg-violet-100"
                    >
                       <span>🎲</span> {t.randomTopic}
                    </button>
                </label>
                <div className="relative">
                  <input
                    type="text"
                    maxLength={MAX_TOPIC_LENGTH}
                    value={inputTopic}
                    onChange={(e) => setInputTopic(e.target.value)}
                    placeholder={
                      selectedMode === SimulationMode.DEBATE
                        ? t.topicPlaceholderDebate
                        : selectedMode === SimulationMode.THEATER
                        ? t.topicPlaceholderTheater
                        : t.topicPlaceholderEducation
                    }
                    className="w-full bg-white border border-slate-300 rounded-xl p-5 pr-16 text-xl text-slate-900 focus:outline-none focus:ring-2 focus:ring-violet-500 transition-all placeholder-slate-400 shadow-inner"
                    onKeyDown={(e) => e.key === 'Enter' && handleStart()}
                  />
                  <div className={`absolute right-4 top-1/2 -translate-y-1/2 text-sm font-mono font-bold ${
                      inputTopic.length >= MAX_TOPIC_LENGTH ? 'text-red-500' : 'text-slate-400'
                  }`}>
                    {inputTopic.length}/{MAX_TOPIC_LENGTH}
                  </div>
                </div>
              </div>

              <div className="flex gap-4">
                  <div className="w-28">
                     <label className="block text-lg font-bold text-slate-700 mb-3">{t.roundsLabel}</label>
                     <input
                        type="number"
                        min={1}
                        max={20}
                        value={numRounds}
                        onChange={(e) => setNumRounds(parseInt(e.target.value) || 0)}
                        className="w-full bg-white border border-slate-300 rounded-xl p-5 text-center text-xl font-bold text-slate-900 focus:outline-none focus:ring-2 focus:ring-violet-500 transition-all shadow-inner"
                     />
                  </div>

                   <div className="w-36">
                     <label className="block text-lg font-bold text-slate-700 mb-3">{t.maxLengthLabel}</label>
                     <div className="relative">
                         <input
                            type="number"
                            min={10}
                            max={500}
                            step={10}
                            value={maxLen}
                            onChange={(e) => setMaxLen(e.target.value)}
                            onBlur={handleMaxLenBlur}
                            className="w-full bg-white border border-slate-300 rounded-xl p-5 text-center text-xl font-bold text-slate-900 focus:outline-none focus:ring-2 focus:ring-violet-500 transition-all shadow-inner"
                         />
                         <span className="absolute right-3 top-1/2 -translate-y-1/2 text-sm text-slate-400 pointer-events-none font-medium">
                             {t.wordUnit}
                         </span>
                     </div>
                  </div>
              </div>
            </div>

            <button
              onClick={handleStart}
              disabled={!inputTopic.trim()}
              className="w-full py-5 rounded-2xl font-bold text-2xl text-white bg-gradient-to-r from-violet-600 to-fuchsia-600 hover:from-violet-500 hover:to-fuchsia-500 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-lg hover:shadow-violet-500/30 flex items-center justify-center gap-3 transform hover:-translate-y-1 active:translate-y-0"
            >
              <span>🎬</span>
              <span>{t.action}</span>
            </button>
          </div>
        )}

        {/* Script Display */}
        {(state.messages.length > 0 || state.isPlaying) && (
           <div className="flex-1 min-h-[500px] flex flex-col relative">
              <div className="flex-1 space-y-4 pb-32">
                  {state.messages.map((msg) => (
                    <ChatBubble key={msg.id} message={msg} language={state.language} mode={state.mode} />
                  ))}

                  {/* Loading / Typing Indicator */}
                  {state.isPlaying && state.currentSpeaker && (
                     <div className="flex w-full justify-center animate-pulse py-4">
                        <div className={`px-6 py-3 rounded-full text-base font-bold border-2 shadow-sm ${
                            state.currentSpeaker === AgentRole.DIRECTOR ? 'border-violet-200 text-violet-700 bg-violet-50' :
                            state.currentSpeaker === AgentRole.ACTOR_A ? 'border-cyan-200 text-cyan-700 bg-cyan-50' :
                            'border-rose-200 text-rose-700 bg-rose-50'
                        }`}>
                           {AGENT_CONFIG[state.currentSpeaker].avatar} {AGENT_CONFIG[state.currentSpeaker].names(state.mode, state.language)} {t.thinking}
                        </div>
                     </div>
                  )}
                  <div ref={scrollRef} />
              </div>

              {/* Floating Action Bar */}
              <div className="fixed bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-4 bg-white/95 backdrop-blur-md border border-slate-200 p-3 pl-4 pr-3 rounded-2xl shadow-2xl z-50 ring-1 ring-black/5">

                 {/* Intervene Button */}
                 <button
                   onClick={() => triggerIntervention()}
                   disabled={!state.isPlaying || state.isIntervening}
                   title={t.interveneTooltip}
                   className={`flex flex-col items-center justify-center w-14 h-14 rounded-xl transition-all ${
                     state.isIntervening 
                      ? "bg-violet-600 text-white animate-pulse shadow-lg" 
                      : "bg-slate-100 hover:bg-violet-50 text-slate-500 hover:text-violet-600 border border-slate-200 hover:border-violet-300"
                   } disabled:opacity-30 disabled:cursor-not-allowed`}
                 >
                   <span className="text-2xl">📢</span>
                 </button>

                 <div className="h-10 w-px bg-slate-300 mx-1"></div>

                 {/* Pause / Resume */}
                 <button 
                    onClick={togglePause}
                    className={`flex items-center gap-3 px-8 h-14 rounded-xl font-bold text-lg transition-all shadow-sm ${
                       state.isPlaying 
                         ? "bg-amber-50 hover:bg-amber-100 text-amber-700 border border-amber-200 hover:border-amber-400" 
                         : "bg-emerald-50 hover:bg-emerald-100 text-emerald-700 border border-emerald-200 hover:border-emerald-400"
                    }`}
                 >
                    <span className="text-2xl">{state.isPlaying ? "⏸" : "▶️"}</span>
                    <span>{state.isPlaying ? t.pause : t.resume}</span>
                 </button>

                 {/* Reset / New Scene */}
                 {!state.isPlaying && (
                     <button 
                        onClick={resetSimulation}
                        className="flex items-center gap-3 px-6 h-14 bg-white hover:bg-slate-50 text-slate-700 hover:text-slate-900 border border-slate-300 hover:border-slate-400 rounded-xl transition-colors font-bold text-lg shadow-sm"
                    >
                        <span>🔄</span>
                        <span className="hidden sm:inline">{t.newScene}</span>
                    </button>
                 )}
              </div>
           </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from "react";
import { Message, AgentRole, Language, SimulationMode } from "../types";
import { AGENT_CONFIG } from "../constants";
import { playAudioData } from "../services/ttsService";

interface ChatBubbleProps {
  message: Message;
  language: Language;
  mode?: SimulationMode; 
}

export const ChatBubble: React.FC<ChatBubbleProps> = ({ message, language, mode = SimulationMode.DEBATE }) => {
  const config = AGENT_CONFIG[message.role];
  const isDirector = message.role === AgentRole.DIRECTOR;

  // Resolve the name function
  const displayName = config.names(mode, language);

  const [isPlaying, setIsPlaying] = useState(false);

  const handleReplay = async () => {
    if (!message.audioBase64 || isPlaying) return;
    setIsPlaying(true);
    await playAudioData(message.audioBase64);
    setIsPlaying(false);
  };

  return (
    <div
      className={`flex w-full mb-8 animate-fade-in ${
        isDirector ? "justify-center" : message.role === AgentRole.ACTOR_A ? "justify-start" : "justify-end"
      }`}
    >
      <div
        className={`flex max-w-[85%] md:max-w-[75%] flex-col ${
          message.role === AgentRole.ACTOR_B ? "items-end" : "items-start"
        }`}
      >
        <div className="flex items-center gap-3 mb-2 px-1">
          <span className="text-3xl filter drop-shadow-sm">{config.avatar}</span>
          <span className={`text-sm md:text-base font-bold uppercase tracking-wider ${
             isDirector ? "text-violet-700" : message.role === AgentRole.ACTOR_A ? "text-cyan-700" : "text-rose-700"
          }`}>
            {displayName}
          </span>
          {message.audioBase64 && (
            <button
              onClick={handleReplay}
              disabled={isPlaying}
              className={`ml-1 p-1.5 rounded-full hover:bg-slate-200 transition-colors ${
                 isPlaying ? "text-green-600 animate-pulse" : "text-slate-400 hover:text-slate-700"
              }`}
              title="Replay Audio"
            >
               {isPlaying ? (
                 <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"></polygon><path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"></path></svg>
               ) : (
                 <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"></polygon><path d="M15.54 8.46a5 5 0 0 1 0 7.07"></path></svg>
               )}
            </button>
          )}
        </div>

        <div
          className={`relative p-6 rounded-3xl shadow-sm border ${
            isDirector
              ? "bg-violet-50 border-violet-200 text-center text-violet-900"
              : message.role === AgentRole.ACTOR_A
              ? "bg-cyan-50 border-cyan-200 text-cyan-950 rounded-tl-none"
              : "bg-rose-50 border-rose-200 text-rose-950 rounded-tr-none"
          }`}
        >
          <p className="whitespace-pre-wrap leading-relaxed text-lg md:text-xl font-medium">
            {message.content}
          </p>
        </div>
      </div>
    </div>
  );
};
